-- OBJECT ROUTINE public/dbo.board_checkallowbyitem
CREATE OR REPLACE FUNCTION public.board_checkallowbyitem(userno integer, itemno integer, itemtype integer, role integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT (SELECT COUNT(*)   FROM Board_AllowAccess WHERE UserNo=board_checkallowbyitem.userno AND ItemNo=  board_checkallowbyitem.itemno AND ItemType=board_checkallowbyitem.itemtype AND  (AllowValue & Role) > 0)
	+(SELECT  COUNT(*) FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo AND OB.UserNo=board_checkallowbyitem.userno
	WHERE  BD.ItemNo=  board_checkallowbyitem.itemno AND BD.ItemType=board_checkallowbyitem.itemtype AND  (BD.AllowValue & Role) > 0);
END;
$function$


-- OBJECT ROUTINE public/dbo.board_checkpermission
CREATE OR REPLACE FUNCTION public.board_checkpermission(itemno integer DEFAULT 95, itemtype integer DEFAULT 1)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF ItemType=2 THEN
		RETURN QUERY
		SELECT CASE WHEN BB.SpecType=1  THEN FALSE ELSE  TRUE END  AS IsPermission,FALSE  AS IsDisablePermission
		FROM Board_Boards BB
		WHERE  ItemNo=BB.BoardNo;
	ELSE
	RETURN QUERY
	SELECT CASE WHEN FC.SpecType=1  THEN FALSE ELSE  TRUE END  AS IsPermission ,
			  FALSE  AS IsDisablePermission
	FROM Board_Folders FC
	WHERE  ItemNo=FC.FolderNo;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_checkpermissionbycontentno
CREATE OR REPLACE FUNCTION public.board_checkpermissionbycontentno(userno integer DEFAULT 6656, contentno integer DEFAULT 5504)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH SHARE AS(
		SELECT U.UserNo ,BS.ContentNo
		FROM Board_Sharers BS
		INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_checkpermissionbycontentno.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
	),
	DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_checkpermissionbycontentno.userno AND OB.IsDefault= TRUE
)
	SELECT COUNT(*) AS AllowValue FROM Board_Contents BC
	INNER JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BB.BoardNo AND ItemType=2 AND UserNo=board_checkpermissionbycontentno.userno
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE  BC.ContentNo= board_checkpermissionbycontentno.contentno AND (BC.RegUserNo=board_checkpermissionbycontentno.userno OR BA.AllowValue=7 OR  D.AllowValue=7 OR  ((BA.AllowAccessNo IS NOT NULL  OR D.AllowAccessNo IS NOT NULL) AND BB.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  BB.SpecType=1));
END;
$function$


