	--	FROM Board_Folders BF
	--    LEFT JOIN Board_HistoryFolder BH ON BH.UserNo=UserNo AND BF.FolderNo=BH.FolderNo
	--	WHERE Enabled = TRUE
	--	ORDER BY BF.SortNo ASC,BF.FolderNo ASC

	--END
