-- OBJECT ROUTINE public/dbo.board_getiosdeviceofusersbydepartment
CREATE OR REPLACE FUNCTION public.board_getiosdeviceofusersbydepartment(listdepartno character varying, delimiter character varying, listuserno character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
SELECT DeviceID, OSVersion, NotificationOptions, TimezoneOffset
	FROM Organization_Users U
	INNER JOIN Board_IOSDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = TRUE
	and U.UserNo in (select * from public."fn_split_array"(ListUserNo,Delimiter))
	UNION
SELECT DeviceID, OSVersion, NotificationOptions, TimezoneOffset
	FROM Organization_Users U
	INNER JOIN Board_IOSDevices A ON A.UserNO = U.UserNo
	WHERE U.Enabled = TRUE
	and U.UserNo in (select o.UserNo
from Organization_BelongToDepartment o
inner join Organization_Departments d on o.departno=d.departno
--inner join Organization_Users u on u.userno=o.userno
where  o.departno in (select * from FN_GetChildDepartNoByDepartNo(ListDepartNo,Delimiter))
--and u.Enabled = TRUE
);
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontent
CREATE OR REPLACE FUNCTION public.board_getlistboardcontent(userno integer DEFAULT 70, boardno integer DEFAULT 1094, curentpage integer DEFAULT 1, pagesize integer DEFAULT 15, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2000-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2026-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT true, titleeffect boolean DEFAULT false, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


    SearchValue := COALESCE(LTRIM(RTRIM(SearchValue)),  '');
    MgDepartment := COALESCE(LTRIM(RTRIM(MgDepartment)), '');
    SortColumn := COALESCE(LTRIM(RTRIM(SortColumn)),   '');
    RETURN QUERY
    WITH
    PERMISSION AS (
        SELECT ItemNo, AllowValue, AllowAccessNo
        FROM   Board_AllowAccess
        WHERE  ItemType = 2 AND UserNo = board_getlistboardcontent.userno AND AllowValue > 0
    ),
    DEPARTPERMISSION AS (
        SELECT BD.ItemNo, BD.AllowValue, BD.AllowAccessNo
        FROM   Board_DepartAllowAccess BD
        INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo = BD.DepartNo
        WHERE  BD.ItemType = 2 AND OB.UserNo = board_getlistboardcontent.userno
          AND  OB.IsDefault = TRUE AND BD.AllowValue > 0
    ),
    USER_DEPART AS (
        SELECT U.UserNo, OB.DepartNo
        FROM   Organization_Users U
        INNER JOIN Organization_BelongToDepartment OB ON OB.UserNo = U.UserNo
        WHERE  U.UserNo = board_getlistboardcontent.userno AND U.Enabled = TRUE
    ),
    SHARE AS (
        SELECT DISTINCT BS.ContentNo FROM Board_Sharers BS
        INNER JOIN USER_DEPART UD ON BS.UserNo   = UD.UserNo
        UNION
        SELECT DISTINCT BS.ContentNo FROM Board_Sharers BS
        INNER JOIN USER_DEPART UD ON BS.DepartNo = UD.DepartNo
    ),
    PERMISSION_BOARD AS (
        SELECT B.BoardNo, B.Name, B.ViewMode, B.SpecType
        FROM   Board_Boards B
        LEFT JOIN PERMISSION       P ON P.ItemNo = B.BoardNo
        LEFT JOIN DEPARTPERMISSION D ON D.ItemNo = B.BoardNo
        WHERE  (B.BoardNo = board_getlistboardcontent.boardno OR BoardNo = 0)
          AND  (IsAdmin = TRUE OR P.AllowValue > 0 OR D.AllowValue > 0 OR B.SpecType = 1)
    ),
    VIEWED AS (
        SELECT DISTINCT ContentNo FROM Board_ViewedLogs WHERE UserNo = board_getlistboardcontent.userno
    ),
    TMP AS (
        SELECT
            BC.BoardNo, BC.ContentNo, BC.Title, BC.IsFile, BC.ViewedCount, BC.RootId,
            BC.TitleEffect, BC.RegDate, BC.ModDate, BC.IsNotice, BC.RegUserNo,
            CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name) WHERE Name=board_getlistboardcontent.langcode) ELSE B.Name END AS BoardName,
            CASE LangCode WHEN 'EN' THEN COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name) WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
            CASE LangCode WHEN 'EN' THEN COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name) WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
            CASE LangCode WHEN 'EN' THEN COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name) WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
            SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) AS RegDateToString,
            CASE WHEN '2020-12-31'::timestamp>BC.RegDate OR BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontent.userno
                 THEN TRUE ELSE FALSE END AS IsReaded,
            ROW_NUMBER() OVER (ORDER BY
                CASE WHEN SortType=0 AND SortColumn=''         THEN BC.RootId    END DESC,
                CASE WHEN SortType=0 AND SortColumn=''         THEN BC.HeadNo    END ASC,
                CASE WHEN SortType=0 AND SortColumn=''         THEN BC.ContentNo END ASC,
                CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice  END DESC,
                CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.RootId    END DESC,
                CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo    END ASC,
                CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.ContentNo END ASC,
                CASE WHEN SortType=0 AND SortColumn='TITLE'      THEN BC.Title       END ASC,
                CASE WHEN SortType=0 AND SortColumn='REGDATE'    THEN BC.RegDate     END ASC,
                CASE WHEN SortType=0 AND SortColumn='VIEWED'     THEN BC.ViewedCount END ASC,
                CASE WHEN SortType=0 AND SortColumn='TYPE'       THEN BC.Type        END ASC,
                CASE WHEN SortType=0 AND SortColumn='ERRORTYPE'  THEN BC.ErrorType   END ASC,
                CASE WHEN SortType=0 AND SortColumn='PERSONTYPE' THEN BC.PersonType  END ASC,
                CASE WHEN SortType=0 AND SortColumn='BOARD' THEN CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name) WHERE Name=board_getlistboardcontent.langcode) ELSE B.Name END END ASC,
                CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN CASE LangCode WHEN 'EN' THEN COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name) WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
                CASE WHEN SortType=0 AND SortColumn='DEPART' THEN CASE LangCode WHEN 'EN' THEN COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name) WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
                CASE WHEN SortType=1 AND SortColumn='TITLE'      THEN BC.Title       END DESC,
                CASE WHEN SortType=1 AND SortColumn='REGDATE'    THEN BC.RegDate     END DESC,
                CASE WHEN SortType=1 AND SortColumn='VIEWED'     THEN BC.ViewedCount END DESC,
                CASE WHEN SortType=1 AND SortColumn='TYPE'       THEN BC.Type        END DESC,
                CASE WHEN SortType=1 AND SortColumn='ERRORTYPE'  THEN BC.ErrorType   END DESC,
                CASE WHEN SortType=1 AND SortColumn='PERSONTYPE' THEN BC.PersonType  END DESC,
                CASE WHEN SortType=1 AND SortColumn='BOARD' THEN CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name) WHERE Name=board_getlistboardcontent.langcode) ELSE B.Name END END DESC,
                CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN CASE LangCode WHEN 'EN' THEN COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name) WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
                CASE WHEN SortType=1 AND SortColumn='DEPART' THEN CASE LangCode WHEN 'EN' THEN COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name) WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC
            ) AS RowNum,
            COUNT(*) OVER () AS TotalRows,
            B.ViewMode AS BoardType, B.SpecType,
            CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR D.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontent.userno
                 THEN TRUE ELSE FALSE END AS IsDelete,
            BC.Type, BC.ErrorType, BC.PersonType, BC.VisitDate, BC.VisitCompleteDate,
            BC.ConstructionName, BC.ApplyTo, BC.MailRecipientNo, BC.MailRecipientName,
            CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date) END AS DayDateView,
            BC.Important, BC.DesignNo, BC.Private, BC.Purpose, BC.RecommendedCount, BC.IsRecommendPublic,
            BC.IsShareAll
        FROM    Board_Contents BC
        INNER JOIN PERMISSION_BOARD  B  ON B.BoardNo     = BC.BoardNo
        LEFT  JOIN Organization_Users       OU ON OU.UserNo     = BC.RegUserNo
        LEFT  JOIN Organization_Positions   OP ON OP.PositionNo = BC.RegPositionNo
        LEFT  JOIN Organization_Departments OD ON OD.DepartNo   = BC.RegDepartNO
        LEFT  JOIN VIEWED                   BV ON BV.ContentNo  = BC.ContentNo
        LEFT  JOIN PERMISSION               P  ON  P.ItemNo     = BC.BoardNo
        LEFT  JOIN DEPARTPERMISSION         D  ON  D.ItemNo     = BC.BoardNo
        LEFT  JOIN SHARE                    S  ON  S.ContentNo  = BC.ContentNo
        WHERE  (BC.BoardNo = board_getlistboardcontent.boardno OR (BoardNo = 0 AND B.ViewMode >= 2))
          AND  BC.Enabled = TRUE
          AND  BC.RegDate       >= board_getlistboardcontent.fromdate
          AND  BC.RegDate       <= board_getlistboardcontent.todate
          AND  (FilterType = 100 OR (FilterType = 1 AND BV.ContentNo IS NULL))
          AND  (TitleEffect = 1 OR (TitleEffect = 0 AND TitleEffect = 0))
          AND  (MgDepartment   = '' OR MgDepartment = BC.PersonType)
          AND  (SearchValue = ''
                OR (SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
                OR (SearchType=1 AND CASE LangCode WHEN 'EN' THEN COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name) WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
                OR (SearchType=2 AND CASE LangCode WHEN 'EN' THEN COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name) WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
                OR (SearchType=3 AND BC.Type             =    board_getlistboardcontent.searchvalue)
                OR (SearchType=4 AND BC.Type             ILIKE '%' || SearchValue || '%')
                OR (SearchType=5 AND BC.ErrorType        ILIKE '%' || SearchValue || '%')
                OR (SearchType=6 AND BC.ApplyTo          ILIKE '%' || SearchValue || '%')
                OR (SearchType=7 AND BC.ConstructionName ILIKE '%' || SearchValue || '%'))
          AND  (IsAdmin = TRUE OR BC.RegUserNo = board_getlistboardcontent.userno OR P.AllowValue = 7 OR D.AllowValue = 7
                OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL) AND B.SpecType=0 AND (BC.IsShareAll = TRUE OR S.ContentNo IS NOT NULL))
                OR ((BC.IsShareAll = TRUE OR S.ContentNo IS NOT NULL) AND B.SpecType=1))
    )
    SELECT
        T.BoardNo, T.ContentNo, T.Title,
        COALESCE(F.Url,'')                                                                AS FileUrl,
        F.Name                                                                          AS FileName,
        REPLACE(REPLACE(COALESCE(F.Url,''),'/Attach/','/Thumbnail/'),'/File/','/Thumbnail/') AS ThumbnailFileUrl,
        T.IsFile, T.BoardName, T.RegUserName, T.RegPositionName, T.RegDepartName,
        COALESCE(VL.ViewedCount, 0)                                                       AS ViewedCount,
        T.RegDateToString, T.RootId, T.TitleEffect, T.IsDelete, T.IsReaded,
        T.TotalRows                                                                     AS Total,
        COALESCE(R.ReplyCount, 0)                                                         AS ReplyCount,
        T.BoardType, T.RegDate, T.ModDate, T.IsNotice,
        CASE WHEN BoardNo<>0 THEN T.Type              ELSE NULL END AS Type,
        CASE WHEN BoardNo<>0 THEN T.ErrorType         ELSE NULL END AS ErrorType,
        CASE WHEN BoardNo<>0 THEN T.PersonType        ELSE NULL END AS PersonType,
        CASE WHEN BoardNo<>0 THEN T.VisitDate         ELSE NULL END AS VisitDate,
        CASE WHEN BoardNo<>0 THEN T.VisitCompleteDate ELSE NULL END AS VisitCompleteDate,
        CASE WHEN BoardNo<>0 THEN T.ConstructionName  ELSE NULL END AS ConstructionName,
        CASE WHEN BoardNo<>0 THEN T.DayDateView       ELSE NULL END AS DayDateView,
        CASE WHEN BoardNo<>0 THEN T.ApplyTo           ELSE NULL END AS ApplyTo,
        CASE WHEN BoardNo<>0 THEN T.MailRecipientNo   ELSE NULL END AS MailRecipientNo,
        CASE WHEN BoardNo<>0 THEN T.MailRecipientName ELSE NULL END AS MailRecipientName,
        CASE WHEN BoardNo<>0 THEN T.Important         ELSE NULL END AS Important,
        CASE WHEN BoardNo<>0 THEN T.DesignNo          ELSE NULL END AS DesignNo,
        CASE WHEN BoardNo<>0 THEN T.Private           ELSE NULL END AS Private,
        CASE WHEN BoardNo<>0 THEN T.RegUserNo         ELSE NULL END AS RegUserNo,
        CASE WHEN BoardNo<>0 THEN T.Purpose           ELSE NULL END AS Purpose,
        CASE WHEN BoardNo<>0 THEN T.RecommendedCount  ELSE NULL END AS RecommendedCount,
        CASE WHEN BoardNo<>0 THEN T.IsRecommendPublic ELSE NULL END AS IsRecommendPublic,
        COALESCE(T.TotalRows,0) - T.RowNum + 1                                            AS RowNumber
    FROM TMP T
    LEFT JOIN LATERAL (
        SELECT COUNT(DISTINCT BV.UserNo) AS ViewedCount
        FROM   Board_ViewedLogs BV
        WHERE  BV.ContentNo = T.ContentNo
          AND  (   T.SpecType      = 1
                OR T.IsShareAll    = TRUE
                OR BV.UserNo      = T.RegUserNo
                OR EXISTS (
                    SELECT 1 FROM Board_Sharers BS
                    WHERE  BS.ContentNo = T.ContentNo
                      AND  (   BS.UserNo   IN (SELECT UserNo   FROM USER_DEPART)
                            OR BS.DepartNo IN (SELECT DepartNo FROM USER_DEPART))
                ))
    ) VL ON TRUE
    LEFT JOIN LATERAL (
        SELECT COUNT(ReplyNo) AS ReplyCount
        FROM   Board_Replies
        WHERE  ContentNo = T.ContentNo
    ) R ON TRUE
    LEFT JOIN LATERAL (
        SELECT Url, Name
        FROM   Board_Files
        WHERE  ContentNo = T.ContentNo
        ORDER BY ContentNo
    ) F ON TRUE
    WHERE  T.RowNum >  (CurentPage - 1) * PageSize
      AND  T.RowNum <= board_getlistboardcontent.curentpage       * PageSize
    ORDER BY T.RowNum;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontent_bk
CREATE OR REPLACE FUNCTION public.board_getlistboardcontent_bk(userno integer DEFAULT 70, boardno integer DEFAULT 1094, curentpage integer DEFAULT 1, pagesize integer DEFAULT 15, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2000-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2026-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT true, titleeffect boolean DEFAULT false, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

IF BoardNo=0 THEN
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontent_bk.userno AND AllowValue>0
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontent_bk.userno AND OB.IsDefault= TRUE AND BD.AllowValue>0
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontent_bk.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
--REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
--	FROM Board_Contents BC
--	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
--	WHERE (BC.BoardNo=BoardNo OR  BoardNo =0 ) AND BC.Enabled = TRUE
--	GROUP BY BC.ContentNo
--	),
PERMISSION_BOARD AS (SELECT B.BoardNo, B.Name,B.ViewMode,B.SpecType
	FROM Board_Boards B
	LEFT JOIN PERMISSION P ON P.ItemNo=B.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE (B.BoardNo=board_getlistboardcontent_bk.boardno OR  BoardNo =0 ) AND ( IsAdmin = TRUE   OR P.AllowValue >0 OR  D.AllowValue >0 OR B.SpecType=1
	)
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=board_getlistboardcontent_bk.userno),
VIEWEDLIST AS (
	SELECT DISTINCT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM (SELECT DISTINCT ContentNo,UserNo FROM Board_ViewedLogs)  BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	INNER JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo AND S.Rn=1
	WHERE  BB.SpecType=1 OR  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,BC.ModDate,BC.IsNotice,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontent_bk.userno)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=0 AND SortColumn='TYPE' THEN  BC.Type END ASC,
		CASE WHEN SortType=0 AND SortColumn='ERRORTYPE' THEN  BC.ErrorType END ASC,
		CASE WHEN SortType=0 AND SortColumn='PERSONTYPE' THEN  BC.PersonType END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC,
		CASE WHEN SortType=1 AND SortColumn='TYPE' THEN  BC.Type END DESC,
		CASE WHEN SortType=1 AND SortColumn='ERRORTYPE' THEN  BC.ErrorType END DESC,
		CASE WHEN SortType=1 AND SortColumn='PERSONTYPE' THEN  BC.PersonType END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR D.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontent_bk.userno THEN TRUE ELSE FALSE END AS IsDelete

	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	INNER JOIN PERMISSION_BOARD B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo AND S.Rn=1
	WHERE (BC.BoardNo=board_getlistboardcontent_bk.boardno OR   (BoardNo =0 AND B.ViewMode>=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=board_getlistboardcontent_bk.fromdate
	AND BC.RegDate<=board_getlistboardcontent_bk.todate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontent_bk.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			OR(SearchType=7 AND BC.ConstructionName ILIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END ILIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontent_bk.userno  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
COALESCE(F.Url,'') AS FileUrl,
F.Name AS FileName,
REPLACE(REPLACE(COALESCE(F.Url,''), '/Attach/', '/Thumbnail/'),'/File/','/Thumbnail/') AS ThumbnailFileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.ModDate,
	T.IsNotice,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,Name,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getlistboardcontent_bk.curentpage*PageSize
ORDER BY T.RowNumber;

ELSE
RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontent_bk.userno AND AllowValue>0
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontent_bk.userno AND OB.IsDefault= TRUE AND BD.AllowValue>0
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontent_bk.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
--REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
--	FROM Board_Contents BC
--	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
--	WHERE (BC.BoardNo=BoardNo OR  BoardNo =0 ) AND BC.Enabled = TRUE
--	GROUP BY BC.ContentNo
--	),
PERMISSION_BOARD AS (SELECT B.BoardNo, B.Name,B.ViewMode,B.SpecType
	FROM Board_Boards B
	LEFT JOIN PERMISSION P ON P.ItemNo=B.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE (B.BoardNo=board_getlistboardcontent_bk.boardno OR  BoardNo =0 ) AND ( IsAdmin = TRUE   OR P.AllowValue >0 OR  D.AllowValue >0 OR B.SpecType=1
	)
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=board_getlistboardcontent_bk.userno),
VIEWEDLIST AS (
	SELECT DISTINCT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM (SELECT DISTINCT ContentNo,UserNo FROM Board_ViewedLogs)  BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	INNER JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo AND S.Rn=1
	WHERE  BB.SpecType=1 OR  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,BC.ModDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontent_bk.userno)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=0 AND SortColumn='TYPE' THEN  BC.Type END ASC,
		CASE WHEN SortType=0 AND SortColumn='ERRORTYPE' THEN  BC.ErrorType END ASC,
		CASE WHEN SortType=0 AND SortColumn='PERSONTYPE' THEN  BC.PersonType END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_bk.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC,
		CASE WHEN SortType=1 AND SortColumn='TYPE' THEN  BC.Type END DESC,
		CASE WHEN SortType=1 AND SortColumn='ERRORTYPE' THEN  BC.ErrorType END DESC,
		CASE WHEN SortType=1 AND SortColumn='PERSONTYPE' THEN  BC.PersonType END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR D.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontent_bk.userno THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	BC.MailRecipientNo,
	BC.MailRecipientName,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView,
	BC.Important,
	BC.DesignNo,
	BC.RegUserNo,
	BC.Private,
	BC.IsNotice,
	BC.Purpose,
	BC.RecommendedCount,
	BC.IsRecommendPublic
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	INNER JOIN PERMISSION_BOARD B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo AND S.Rn=1
	WHERE (BC.BoardNo=board_getlistboardcontent_bk.boardno OR   (BoardNo =0 AND B.ViewMode>=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=board_getlistboardcontent_bk.fromdate
	AND BC.RegDate<=board_getlistboardcontent_bk.todate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND  BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontent_bk.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			OR(SearchType=7 AND BC.ConstructionName ILIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END ILIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontent_bk.userno  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
COALESCE(F.Url,'') AS FileUrl,
F.Name AS FileName,
REPLACE(REPLACE(COALESCE(F.Url,''), '/Attach/', '/Thumbnail/'),'/File/','/Thumbnail/') AS ThumbnailFileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.ModDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	T.MailRecipientNo,
	T.MailRecipientName,
	T.Important,
	T.DesignNo,
	T.Private,
	T.RegUserNo,
	T.IsNotice,
	T.Purpose,
	T.RecommendedCount,
	T.IsRecommendPublic,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,Name,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getlistboardcontent_bk.curentpage*PageSize
ORDER BY T.RowNumber;
END IF;


--LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R  ON R.ContentNo=T.ContentNo
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontent_search
CREATE OR REPLACE FUNCTION public.board_getlistboardcontent_search(userno integer DEFAULT 70, boardno integer DEFAULT 1087, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2015-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT false, titleeffect boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    query character varying;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontent_search.userno
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontent_search.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontent_search.boardno OR  BoardNo =0 ) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=board_getlistboardcontent_search.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title, BC.Content ,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_search.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontent_search.userno)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_search.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontent_search.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontent_search.userno THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontent_search.boardno OR   (BoardNo =0 AND B.ViewMode=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=board_getlistboardcontent_search.fromdate
	AND BC.RegDate<=board_getlistboardcontent_search.todate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontent_search.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END ILIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontent_search.userno OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.Content,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getlistboardcontent_search.curentpage*PageSize
ORDER BY T.RowNumber;
--	CASE WHEN SortType=0 AND SortColumn='' THEN T.RootId END DESC,
--	CASE WHEN SortType=0 AND SortColumn='' THEN  T.ContentNo END ASC,
--	CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  T.Title END ASC,
--	CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  T.BoardName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  T.RegUserName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  T.RegDepartName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN  T.RegDateToString END ASC,
--	CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  T.ViewedCount END ASC,
--	CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  T.Title END DESC,
--	CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  T.BoardName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN  T.RegUserName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  T.RegDepartName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  T.RegDateToString END DESC,
--	CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  T.ViewedCount END DESC


--LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R  ON R.ContentNo=T.ContentNo
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontentbyfolder
CREATE OR REPLACE FUNCTION public.board_getlistboardcontentbyfolder(userno integer DEFAULT 70, boardlist character varying DEFAULT ',1159,1158,1157'::character varying, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2011-01-01 19:20:19.717'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-09-30 19:20:19.717'::timestamp without time zone, isadmin boolean DEFAULT true, titleeffect boolean DEFAULT false, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontentbyfolder.userno
),
DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontentbyfolder.userno AND OB.IsDefault= TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontentbyfolder.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
PERMISSION_BOARD AS (SELECT B.BoardNo, B.Name,B.ViewMode,B.SpecType
	FROM Board_Boards B
	LEFT JOIN PERMISSION P ON P.ItemNo=B.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE B.BoardNo  IN (SELECT * FROM fnStringToListInt(BoardList))  AND ( IsAdmin = TRUE   OR   P.AllowValue >0 OR  D.AllowValue >0 OR B.SpecType=1 )
	),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo IN (SELECT * FROM fnStringToListInt(BoardList))) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (
	SELECT DISTINCT UserNo,ContentNo
	FROM Board_ViewedLogs
	WHERE UserNo=board_getlistboardcontentbyfolder.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
)
,TMP AS (
	SELECT BC.ContentNo,BC.BoardNo,BC.Title,BC.IsFile,BC.ViewedCount,BC.RegDate,BC.ModDate,BC.RootId,BC.TitleEffect,T.Url AS FileUrl,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontentbyfolder.userno) THEN TRUE ELSE FALSE END AS IsReaded ,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentbyfolder.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentbyfolder.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentbyfolder.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
	) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR D.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	BC.MailRecipientNo,
	BC.MailRecipientName,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView,
	BC.Important,
	BC.DesignNo,
	BC.RegUserNo,
	BC.Private,
	BC.IsNotice,
	BC.Purpose
	FROM BOARD_CONTENTS BC
	LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	INNER JOIN PERMISSION_BOARD B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	--LEFT JOIN Organization_BelongToDepartment OB ON OB.UserNo=OU.UserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo And S.Rn=1
	WHERE (BC.BoardNo IN (SELECT * FROM fnStringToListInt(BoardList))) AND BC.Enabled = TRUE AND BC.RegDate>=board_getlistboardcontentbyfolder.fromdate AND BC.RegDate<=board_getlistboardcontentbyfolder.todate
	AND B.ViewMode>=2
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND BC.TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontentbyfolder.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			OR(SearchType=7 AND BC.ConstructionName ILIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END ILIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontentbyfolder.userno OR P.AllowValue=7 OR D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND  B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)AND  B.SpecType=1))
) ,
Total AS (Select count(*) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
F.Url AS FileUrl,
--T.FileUrl,
T.IsFile,
--T.ViewedCount ,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
CONVERT(text, T.RegDate, 120) as RegDateToString,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
T.RootId,
T.IsDelete ,
T.IsReaded,
T.TitleEffect,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
--R.ReplyCount,
T.BoardType,
T.RegDate,
T.ModDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	T.MailRecipientNo,
	T.MailRecipientName,
	T.Important,
	T.DesignNo,
	T.Private,
		T.IsNotice,
	T.RegUserNo,
	T.Purpose,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getlistboardcontentbyfolder.curentpage*PageSize
ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontentsearch
CREATE OR REPLACE FUNCTION public.board_getlistboardcontentsearch(userno integer DEFAULT 70, boardno integer DEFAULT 1087, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2015-07-08 00:00:01'::timestamp without time zone, todate timestamp without time zone DEFAULT '2022-07-09 00:00:01'::timestamp without time zone, isadmin boolean DEFAULT false, titleeffect boolean DEFAULT true, mgdepartment character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    query character varying;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontentsearch.userno
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontentsearch.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontentsearch.boardno OR  BoardNo =0 ) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	),
VIEWED AS (SELECT DISTINCT UserNo,ContentNo
FROM Board_ViewedLogs
WHERE UserNo=board_getlistboardcontentsearch.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title, BC.Content ,BC.IsFile,BC.ViewedCount,BC.RootId,BC.TitleEffect,BC.RegDate,--T.Url AS FileUrl,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentsearch.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontentsearch.userno)  THEN TRUE ELSE FALSE END AS IsReaded ,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentsearch.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontentsearch.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
		) AS RowNumber,
	B.ViewMode AS BoardType,
	B.SpecType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=board_getlistboardcontentsearch.userno THEN TRUE ELSE FALSE END AS IsDelete ,
	BC.Type,
	BC.ErrorType,
	BC.PersonType,
	BC.VisitDate,
	BC.VisitCompleteDate,
	BC.ConstructionName,
	BC.ApplyTo,
	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView
	FROM BOARD_CONTENTS BC
	--LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) T ON T.ContentNo=BC.ContentNo AND Rn=1
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getlistboardcontentsearch.boardno OR   (BoardNo =0 AND B.ViewMode=2))

	AND BC.Enabled = TRUE
	AND BC.RegDate>=board_getlistboardcontentsearch.fromdate
	AND BC.RegDate<=board_getlistboardcontentsearch.todate
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontentsearch.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			)
		-- CASE SearchType
		--	WHEN 0 THEN BC.Title
		--	WHEN 1 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--	WHEN 2 THEN CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END
		--	WHEN 3 THEN BC.Type
		--	ELSE CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END
		--END ILIKE '%' || SearchValue || '%')
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontentsearch.userno OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
) ,
Total AS (Select MAX(RowNumber) as ToTal FROM TMP)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
T.Content,
F.Url AS FileUrl,
T.IsFile,
T.BoardName ,
T.RegUserName,
T.RegPositionName,
T.RegDepartName,
COALESCE(VL.ViewedCount,0) AS ViewedCount,
T.RegDateToString,
T.RootId,
T.TitleEffect,
T.IsDelete ,
T.IsReaded,
c.Total,
COALESCE(R.ReplyCount,0) AS ReplyCount,
T.BoardType,
T.RegDate,
T.Type,
	T.ErrorType,
	T.PersonType,
	T.VisitDate,
	T.VisitCompleteDate,
	T.ConstructionName,
	T.DayDateView,
	T.ApplyTo,
	c.Total -T.RowNumber +1 AS RowNumber
FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R ON R.ContentNo=T.ContentNo
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getlistboardcontentsearch.curentpage*PageSize
ORDER BY T.RowNumber;
--	CASE WHEN SortType=0 AND SortColumn='' THEN T.RootId END DESC,
--	CASE WHEN SortType=0 AND SortColumn='' THEN  T.ContentNo END ASC,
--	CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  T.Title END ASC,
--	CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  T.BoardName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  T.RegUserName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  T.RegDepartName END ASC,
--	CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN  T.RegDateToString END ASC,
--	CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  T.ViewedCount END ASC,
--	CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  T.Title END DESC,
--	CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  T.BoardName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN  T.RegUserName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  T.RegDepartName END DESC,
--	CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  T.RegDateToString END DESC,
--	CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  T.ViewedCount END DESC


--LEFT JOIN (SELECT BR.ContentNo,COUNT(BR.ReplyNo) AS ReplyCount FROM Board_Replies BR GROUP BY BR.ContentNo)R  ON R.ContentNo=T.ContentNo
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistboardcontenttoexcel
CREATE OR REPLACE FUNCTION public.board_getlistboardcontenttoexcel(userno integer DEFAULT 70, boardlist character varying DEFAULT ',0'::character varying, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, langcode character varying DEFAULT 'EN'::character varying, filtertype integer DEFAULT 100, searchtype integer DEFAULT 0, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, sorttype integer DEFAULT 0, fromdate timestamp without time zone DEFAULT '2011-01-01 19:20:19.717'::timestamp without time zone, todate timestamp without time zone DEFAULT '2033-09-30 19:20:19.717'::timestamp without time zone, isadmin boolean DEFAULT true, titleeffect boolean DEFAULT false, mgdepartment character varying DEFAULT ''::character varying, contentnos character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getlistboardcontenttoexcel.userno
),
DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getlistboardcontenttoexcel.userno AND OB.IsDefault= TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo,ROW_NUMBER() OVER(PARTITION BY BS.ContentNo  ORDER BY BS.ContentNo ASC) AS Rn
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getlistboardcontenttoexcel.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
VIEWED AS (
	SELECT DISTINCT UserNo,ContentNo
	FROM Board_ViewedLogs
	WHERE UserNo=board_getlistboardcontenttoexcel.userno),
VIEWEDLIST AS (
	SELECT BV.ContentNo, COUNT(BV.UserNo) AS ViewedCount
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo
	LEFT JOIN SHARE S ON S.ContentNo=BV.ContentNo
	WHERE  BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo
	GROUP BY BV.ContentNo
)
,TMP AS (
	SELECT BC.ContentNo, BC.Title,BC.ViewedCount,BC.RegDate,BC.ModDate,BC.RootId,
	SUBSTRING(TO_CHAR(BC.RegDate, 'YYYY-MM-DD HH24:MI:SS'),3,14) as RegDateToString,
	CASE WHEN '2020-12-31'::timestamp> BC.RegDate OR(BV.ContentNo IS NOT NULL OR BC.RegUserNo=board_getlistboardcontenttoexcel.userno) THEN TRUE ELSE FALSE END AS IsReaded ,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontenttoexcel.langcode) ELSE B.Name END AS BoardName ,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.IsNotice END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.RootId END DESC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN BC.HeadNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='LISTSORT' THEN  BC.ContentNo END ASC,
		CASE WHEN SortType=0 AND SortColumn='TITLE' THEN  BC.Title END ASC,
		CASE WHEN SortType=0 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontenttoexcel.langcode) ELSE B.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGUSER' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END ASC,
		CASE WHEN SortType=0 AND SortColumn='REGDATE' THEN BC.RegDate END ASC,
		CASE WHEN SortType=0 AND SortColumn='VIEWED' THEN  BC.ViewedCount END ASC,
		CASE WHEN SortType=1 AND SortColumn='TITLE' THEN  BC.Title END DESC,
		CASE WHEN SortType=1 AND SortColumn='BOARD' THEN  CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistboardcontenttoexcel.langcode) ELSE B.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGUSER' THEN   CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='DEPART' THEN  CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END END DESC,
		CASE WHEN SortType=1 AND SortColumn='REGDATE' THEN  BC.RegDate END DESC,
		CASE WHEN SortType=1 AND SortColumn='VIEWED' THEN  BC.ViewedCount END DESC
	) AS RowNumber,


	CASE WHEN BC.DateView IS NULL THEN NULL ELSE (BC.DateView::date - BC.RegDate::date)  END AS DayDateView,
	BC.Content
	FROM BOARD_CONTENTS BC
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	--LEFT JOIN Organization_BelongToDepartment OB ON OB.UserNo=OU.UserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	LEFT JOIN VIEWED BV ON BV.ContentNo=BC.ContentNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo And S.Rn=1
	WHERE (0 IN (SELECT * FROM fnStringToListInt(BoardList)) OR BC.BoardNo IN (SELECT * FROM fnStringToListInt(BoardList))) AND BC.Enabled = TRUE AND BC.RegDate>=board_getlistboardcontenttoexcel.fromdate AND BC.RegDate<=board_getlistboardcontenttoexcel.todate
	AND B.ViewMode>=2
	AND (FilterType=100 OR (FilterType=1 AND BV.ContentNo IS NULL))
	AND (TitleEffect=1 OR (TitleEffect=0 AND BC.TitleEffect=0))
	AND (COALESCE(MgDepartment,'')='' OR MgDepartment=BC.PersonType)
	AND (COALESCE(SearchValue,'')=''
			OR(SearchType=0 AND BC.Title ILIKE '%' || SearchValue || '%')
			OR(SearchType=1 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=2 AND CASE LangCode WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END ILIKE '%' || SearchValue || '%')
			OR(SearchType=3 AND BC.Type= board_getlistboardcontenttoexcel.searchvalue)
			OR(SearchType=4 AND BC.Type ILIKE '%' || SearchValue || '%')
			OR(SearchType=5 AND BC.ErrorType ILIKE '%' || SearchValue || '%')
			OR(SearchType=6 AND BC.ApplyTo ILIKE '%' || SearchValue || '%')
			)
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getlistboardcontenttoexcel.userno OR P.AllowValue=7 OR D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND  B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)AND  B.SpecType=1))
	AND (COALESCE(ContentNos,'')=''  OR BC.ContentNo IN (SELECT * FROM fnStringToListInt(ContentNos)))
) ,
Total AS (Select count(*) as ToTal FROM TMP)
SELECT
c.Total -T.RowNumber +1 AS RowNumber,
T.Title,
COALESCE(T.Content,'') AS Content ,
COALESCE(T.BoardName,'') AS BoardName ,
(T.RegUserName || ' - ' || T.RegPositionName) AS  RegUserName,
COALESCE(T.RegPositionName,'') AS RegPositionName ,
COALESCE(T.RegDepartName,'') AS RegDepartName ,
T.RegDate,
T.ModDate,
COALESCE(VL.ViewedCount,0) AS ViewedCount

FROM TMP T
LEFT JOIN Total c ON c.Total>0
LEFT JOIN VIEWEDLIST VL ON VL.ContentNo=T.ContentNo
--INNER JOIN REP R ON R.ContentNo=T.ContentNo
ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistcommentsetting
CREATE OR REPLACE FUNCTION public.board_getlistcommentsetting(langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getlistcommentsetting.langcode) ELSE B.Name END AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_CommentSetting W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE
	ORDER BY RegDate DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistconverturlfile
CREATE OR REPLACE FUNCTION public.board_getlistconverturlfile()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
SELECT * FROM Board_Files;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistnoticepermission
CREATE OR REPLACE FUNCTION public.board_getlistnoticepermission(itemno integer DEFAULT 25, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode character varying DEFAULT 'EN'::character varying, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, searchvalue character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    total bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	Total := (SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
	RETURN QUERY
	WITH RECURSIVE RootDeparts AS (
		  SELECT *
		  FROM Organization_Departments
		  WHERE DepartNo = board_getlistnoticepermission.departno
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 BelongToDepartment AS(
			SELECT T.*,ROW_NUMBER() OVER(PARTITION BY T.UserNo,T.DepartNo ORDER BY T.IsDefault) AS Nm FROM ORGANIZATION_BelongToDepartment T
	),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER (PARTITION BY U.Enabled  ORDER BY
					CASE WHEN  SortColumn='' THEN  CASE LanguageCode WHEN 'EN' THEN  COALESCE(U.Name_EN,U.Name) WHEN 'VN' THEN  COALESCE(U.Name_VN,U.Name) WHEN 'CH' THEN COALESCE(U.Name_CH,U.Name)  WHEN 'JP' THEN COALESCE(U.Name_JP,U.Name) ELSE U.Name END END ASC,
					CASE WHEN  SortColumn='USERNAME' THEN  CASE LanguageCode WHEN 'EN' THEN  COALESCE(U.Name_EN,U.Name) WHEN 'VN' THEN  COALESCE(U.Name_VN,U.Name) WHEN 'CH' THEN COALESCE(U.Name_CH,U.Name)  WHEN 'JP' THEN COALESCE(U.Name_JP,U.Name) ELSE U.Name END END DESC
		) AS RowNum ,
			U.Name,
            U.UserId,
			U.UserNo,
			OB.DepartNo,
			OB.PositionNo,
			CASE WHEN LanguageCode='EN' THEN OD.Name_EN WHEN LanguageCode='VN' THEN OD.Name_VN WHEN LanguageCode='CH' THEN OD.Name_CH WHEN LanguageCode='JP' THEN OD.Name_JP ELSE OD.Name  END AS DepartName,
			CASE WHEN LanguageCode='EN' THEN OP.NAME_EN WHEN LanguageCode='VN' THEN OP.Name_VN WHEN LanguageCode='CH' THEN OP.Name_CH WHEN LanguageCode='JP' THEN OP.Name_JP ELSE OP.Name END  AS PositionName,
			CAST( CASE WHEN UP.AllowValue>0 THEN 1  ELSE 0 END AS BIT) AS IsAdmin
		FROM ORGANIZATION_USERS U
		LEFT JOIN Board_NoticePermission UP ON UP.UserNo=U.UserNo
		INNER JOIN BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.Nm=1
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=board_getlistnoticepermission.applicationno
		WHERE  (DepartNo=0 OR  OD.DepartNo IN (SELECT DepartNo FROM RootDeparts)) AND(OP.PositionNo=board_getlistnoticepermission.positionno OR PositionNo=0) AND U.Enabled = TRUE AND (U.UserID ILIKE '%' || SearchValue || '%' OR U.Name ILIKE '%' || SearchValue || '%'  )
	)

	SELECT (SELECT COUNT(*) AS Total  FROM USERS U) AS Total, U.Name,U.UserId,U.UserNo,U.DepartNo,U.PositionNo,U.DepartName,U.PositionName,U.IsAdmin
	FROM USERS U--,TOTAL T
	WHERE  U.RowNum >board_getlistnoticepermission.pagesize*(PageNumber-1) AND U.RowNum <=board_getlistnoticepermission.pagesize*PageNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getlistuserpermission
CREATE OR REPLACE FUNCTION public.board_getlistuserpermission(itemno integer DEFAULT 25, itemtype integer DEFAULT 1, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode character varying DEFAULT 'EN'::character varying, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, ispermission boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    total bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	--DECLARE ParentFolderNo INT;
	--IF(ItemType=1)
	--	SET ParentFolderNo= (SELECT ParentNo FROM Board_Folders  WHERE  FolderNo=ItemNo)
	--ELSE
	--	SET ParentFolderNo= (SELECT FolderNo FROM Board_Boards  WHERE  BoardNo=ItemNo);
	Total := (SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
	RETURN QUERY
	WITH
	--UserParentPermistions AS(
	--	SELECT * FROM Board_AllowAccess WHERE ItemNo=ParentFolderNo AND ItemType=1
	--),
	UserPermistions as (
		SELECT DISTINCT BA.UserNo,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =2 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsRead ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsWrite ,
		FALSE  AS DisableAdmin ,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS DisableWrite ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue=4 OR BA.AllowValue=6 THEN TRUE ELSE FALSE END AS DisableRead
		FROM Board_AllowAccess BA
		--LEFT JOIN UserParentPermistions UP ON UP.UserNo=BA.UserNo AND UP.ItemNo=ParentFolderNo AND UP.ItemType=1
		WHERE BA.ItemNo=board_getlistuserpermission.itemno AND BA.ItemType=board_getlistuserpermission.itemtype
	),
	RootDeparts AS (
		  SELECT *
		  FROM Organization_Departments
		  WHERE DepartNo = board_getlistuserpermission.departno
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 BelongToDepartment AS(
			SELECT T.*,ROW_NUMBER() OVER(PARTITION BY T.UserNo,T.DepartNo ORDER BY T.IsDefault) AS Nm FROM ORGANIZATION_BelongToDepartment T
	),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER ( ORDER BY U.UserNo ) AS RowNum ,
			U.Name,
            U.UserId,
			U.UserNo,
			OB.DepartNo,
			OB.PositionNo,
			CASE WHEN LanguageCode='EN' THEN OD.Name_EN WHEN LanguageCode='VN' THEN OD.Name_VN WHEN LanguageCode='CH' THEN OD.Name_CH WHEN LanguageCode='JP' THEN OD.Name_JP ELSE OD.Name  END AS DepartName,
			CASE WHEN LanguageCode='EN' THEN OP.NAME_EN WHEN LanguageCode='VN' THEN OP.Name_VN WHEN LanguageCode='CH' THEN OP.Name_CH WHEN LanguageCode='JP' THEN OP.Name_JP ELSE OP.Name END  AS PositionName,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsAdmin IS NOT NULL THEN  UP.IsAdmin ELSE FALSE END AS IsAdmin ,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsRead ELSE FALSE END AS IsRead ,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsWrite ELSE FALSE END AS IsWrite ,
			CASE WHEN IsPermission = FALSE --OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE  WHEN UP.DisableAdmin IS NOT NULL THEN  UP.DisableAdmin ELSE FALSE END AS DisableAdmin,
			CASE WHEN IsPermission = FALSE --OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE WHEN UP.DisableRead IS NOT NULL THEN  UP.DisableRead ELSE FALSE END AS DisableRead,
			CASE WHEN IsPermission = FALSE --OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL
			THEN TRUE  WHEN UP.DisableWrite IS NOT NULL THEN  UP.DisableWrite ELSE FALSE END AS DisableWrite
			FROM ORGANIZATION_USERS U
		LEFT JOIN UserPermistions UP ON UP.UserNo=U.UserNo
		INNER JOIN BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.Nm=1
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=board_getlistuserpermission.applicationno
		WHERE (DepartNo=0 OR  OD.DepartNo IN (SELECT DepartNo FROM RootDeparts)) AND(OP.PositionNo=board_getlistuserpermission.positionno OR PositionNo=0) AND U.Enabled = TRUE
	)--,
	--TOTAL AS (SELECT COUNT(*) AS Total  FROM USERS U)
	SELECT (SELECT COUNT(*) AS Total  FROM USERS U) AS Total, U.Name,U.UserId,U.UserNo,U.DepartNo,U.PositionNo,U.DepartName,U.PositionName,U.IsAdmin,U.IsRead,U.IsWrite,U.DisableAdmin,U.DisableRead,U.DisableWrite
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(ParentFolderNo,0)=0 THEN  U.DisableAdmin ELSE  TRUE  END AS DisableAdmin,
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(ParentFolderNo,0)=0 THEN  U.DisableRead ELSE TRUE END AS DisableRead,
	--CASE WHEN  UP.AllowValue IS NOT NULL OR COALESCE(ParentFolderNo,0)=0 THEN  U.DisableWrite ELSE TRUE END AS DisableWrite
	FROM USERS U--,TOTAL T
	--LEFT JOIN UserParentPermistions  UP ON UP.UserNo=U.UserNo
	WHERE U.RowNum >board_getlistuserpermission.pagesize*(PageNumber-1) AND U.RowNum <=board_getlistuserpermission.pagesize*PageNumber;

	--SET NOCOUNT ON;
	--DECLARE Total BIGINT;
	--DECLARE ParentFolderNo INT;
	--IF(ItemType=1)
	--	SET ParentFolderNo= (SELECT ParentNo FROM Board_Folders  WHERE  FolderNo=ItemNo)
	--ELSE
	--	SET ParentFolderNo= (SELECT FolderNo FROM Board_Boards  WHERE  BoardNo=ItemNo)
	--SET Total =(SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
	--WITH
	--UserParentPermistions AS(
	--	SELECT * FROM Board_AllowAccess WHERE ItemNo=ParentFolderNo AND ItemType=1
	--),
	--UserPermistions as (
	--	SELECT DISTINCT BA.UserNo,
	--	CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
	--	CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =2 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsRead ,
