-- OBJECT ROUTINE public/dbo.board_getlistuserpermissiontoexcel
CREATE OR REPLACE FUNCTION public.board_getlistuserpermissiontoexcel(itemno integer DEFAULT 25, itemtype integer DEFAULT 1, applicationno integer DEFAULT 7, departno integer DEFAULT 1, positionno integer DEFAULT 0, languagecode character varying DEFAULT 'EN'::character varying, pagenumber integer DEFAULT 1, pagesize integer DEFAULT 10, ispermission boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    total bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	--DECLARE ParentFolderNo INT;
	--IF(ItemType=1)
	--	SET ParentFolderNo= (SELECT ParentNo FROM Board_Folders  WHERE  FolderNo=ItemNo)
	--ELSE
	--	SET ParentFolderNo= (SELECT FolderNo FROM Board_Boards  WHERE  BoardNo=ItemNo);
	Total := (SELECT COUNT(UserId) FROM ORGANIZATION_USERS);
	RETURN QUERY
	WITH
	--UserParentPermistions AS(
	--	SELECT * FROM Board_AllowAccess WHERE ItemNo=ParentFolderNo AND ItemType=1
	--),
	UserPermistions as (
		SELECT DISTINCT BA.UserNo,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =2 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsRead ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue =4 OR BA.AllowValue =6 THEN TRUE ELSE FALSE END AS IsWrite ,
		FALSE  AS DisableAdmin ,
		CASE WHEN BA.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS DisableWrite ,
		CASE WHEN BA.AllowValue%2<>0 OR BA.AllowValue=4 OR BA.AllowValue=6 THEN TRUE ELSE FALSE END AS DisableRead
		FROM Board_AllowAccess BA
		--LEFT JOIN UserParentPermistions UP ON UP.UserNo=BA.UserNo AND UP.ItemNo=ParentFolderNo AND UP.ItemType=1
		WHERE BA.ItemNo=board_getlistuserpermissiontoexcel.itemno AND BA.ItemType=board_getlistuserpermissiontoexcel.itemtype
	),
	RootDeparts AS (
		  SELECT *
		  FROM Organization_Departments
		  WHERE DepartNo = board_getlistuserpermissiontoexcel.departno
		  UNION ALL
		  SELECT OD.*
		  FROM Organization_Departments OD
		  JOIN RootDeparts R ON OD.ParentNo = R.DepartNo
	 ),
	 BelongToDepartment AS(
			SELECT T.*,ROW_NUMBER() OVER(PARTITION BY T.UserNo,T.DepartNo ORDER BY T.IsDefault) AS Nm FROM ORGANIZATION_BelongToDepartment T
	),
	 USERS AS(
		SELECT	ROW_NUMBER() OVER ( ORDER BY U.UserNo ) AS RowNum ,
			U.Name,
            U.UserId,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsAdmin IS NOT NULL THEN  UP.IsAdmin ELSE FALSE END AS IsAdmin ,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsRead ELSE FALSE END AS IsRead ,
			CASE WHEN IsPermission = FALSE OR SP.UserNo IS NOT NULL OR MP.UserNo IS NOT NULL THEN TRUE  WHEN UP.IsRead IS NOT NULL THEN  UP.IsWrite ELSE FALSE END AS IsWrite
			FROM ORGANIZATION_USERS U
		LEFT JOIN UserPermistions UP ON UP.UserNo=U.UserNo
		INNER JOIN BelongToDepartment OB ON OB.UserNo=U.UserNo AND OB.Nm=1
		INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo
		INNER JOIN Organization_Positions OP ON OP.PositionNo=OB.PositionNo
		LEFT JOIN Authority_SitePermissions SP ON SP.UserNo=U.UserNo AND SP.PermissionType=1
		LEFT JOIN Authority_ModulePermission MP ON MP.UserNo=U.UserNo AND MP.ApplicationNo=board_getlistuserpermissiontoexcel.applicationno
		WHERE (DepartNo=0 OR  OD.DepartNo IN (SELECT DepartNo FROM RootDeparts)) AND(OP.PositionNo=board_getlistuserpermissiontoexcel.positionno OR PositionNo=0) AND U.Enabled = TRUE
	)--,
	--TOTAL AS (SELECT COUNT(*) AS Total  FROM USERS U)
	SELECT U.UserId,U.Name AS UserName,U.IsAdmin AS "Admin" ,U.IsWrite As Write ,U.IsRead AS "Read"
	FROM USERS U--,TOTAL T
	--LEFT JOIN UserParentPermistions  UP ON UP.UserNo=U.UserNo
	WHERE U.RowNum >board_getlistuserpermissiontoexcel.pagesize*(PageNumber-1) AND U.RowNum <=board_getlistuserpermissiontoexcel.pagesize*PageNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getmaxsortoftree
CREATE OR REPLACE FUNCTION public.board_getmaxsortoftree(parentno integer DEFAULT 115)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
WITH RECURSIVE SORT AS (
select max(SortNo) AS SortNo from Board_Folders where ParentNo= board_getmaxsortoftree.parentno
UNION
select max(SortNo)  AS SortNo from Board_Boards where FolderNo = board_getmaxsortoftree.parentno)
SELECT MAX(SortNo) FROM SORT;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getmultiwidget
CREATE OR REPLACE FUNCTION public.board_getmultiwidget(langcode character varying DEFAULT 'EN'::character varying, userno integer DEFAULT 6656, isadmin boolean DEFAULT false)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	WITH DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo
		FROM Board_DepartAllowAccess BD
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE BD.ItemType=2 AND OB.UserNo=board_getmultiwidget.userno AND OB.IsDefault= TRUE
)
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		COALESCE(CASE WHEN STRPOS(B.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(B.Name)  WHERE B.NAME=board_getmultiwidget.langcode),(SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getmultiwidget.langcode)) ELSE B.Name END,'') AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_MultiBoardWidget W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.UserNo=board_getmultiwidget.userno
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo
	WHERE W.IsDelete = FALSE  AND (IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
	ORDER BY W.Sort DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getnewboardcontent
CREATE OR REPLACE FUNCTION public.board_getnewboardcontent(userno integer DEFAULT 120, countperpage integer DEFAULT 10, currentpageindex integer DEFAULT 1, languagesign character varying DEFAULT 'KO'::character varying, isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH PERMISSION AS (
	Select *
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getnewboardcontent.userno
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getnewboardcontent.userno --AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),

TMP AS (
	SELECT BC.*,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RegDate DESC) AS RowNumber,
	B.ViewMode AS BoardType,
	CASE WHEN IsAdmin = TRUE OR P.AllowValue%2<>0 OR BC.RegUserNo=board_getnewboardcontent.userno THEN TRUE ELSE FALSE END AS IsDelete
	FROM BOARD_ContentS BC
	INNER JOIN Board_NewBoardWidget W ON W.BoardNo=BC.BoardNo AND W.Type=3  And W.IsDelete= FALSE
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE
	BC.Enabled = TRUE
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getnewboardcontent.userno OR  (P.AllowAccessNo IS NOT NULL AND B.SpecType=0) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1))

)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,

T.RegDate
FROM TMP T
WHERE T.RowNumber>(CurrentPageIndex-1)*CountPerPage AND T.RowNumber<=board_getnewboardcontent.currentpageindex*CountPerPage
ORDER BY T.RootId DESC,T.ContentNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getnewboardwidget
CREATE OR REPLACE FUNCTION public.board_getnewboardwidget(langcode character varying DEFAULT 'EN'::character varying, type integer DEFAULT 1)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getnewboardwidget.langcode) ELSE B.Name END AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE AND W.Type=board_getnewboardwidget.type
	ORDER BY W.Sort DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getopenfolder
CREATE OR REPLACE FUNCTION public.board_getopenfolder(userno integer DEFAULT 70)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
SELECT COALESCE(IsOpen,CAST('FALSE' AS BIT)) FROM Board_HistoryFolder WHERE UserNo=board_getopenfolder.userno AND IsOpen= FALSE;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getprenextcontent
CREATE OR REPLACE FUNCTION public.board_getprenextcontent(contentno integer DEFAULT 4946, boardno integer DEFAULT 0, languagesign character varying DEFAULT 'EN'::character varying, userno integer DEFAULT 70, isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH PERMISSION AS (
	Select *
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getprenextcontent.userno
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getprenextcontent.userno AND OB.IsDefault= TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getprenextcontent.userno --AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
REP AS (SELECT BC.ContentNo,Count(BR.ReplyNo) AS ReplyCount
	FROM Board_Contents BC
	LEFT JOIN Board_Replies BR ON BR.ContentNo=BC.ContentNo
	WHERE (BC.BoardNo=board_getprenextcontent.boardno OR  BoardNo =0 ) AND BC.Enabled = TRUE
	GROUP BY BC.ContentNo
	)
,TMP AS (
	SELECT --BC.*,--T.Url AS FileUrl,
	BC.ContentNo,BC.Title,BC.ModUserName,BC.Private,BC.IsShareAll,
	CASE WHEN STRPOS(B.Name, '{')>0 THEN (SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getprenextcontent.languagesign) ELSE B.Name END AS BoardName ,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OU.Name_EN,OU.Name) WHEN 'VN' THEN  COALESCE(OU.Name_VN,OU.Name) WHEN 'CH' THEN COALESCE(OU.Name_CH,OU.Name)  WHEN 'JP' THEN COALESCE(OU.Name_JP,OU.Name) ELSE OU.Name END AS RegUserName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OP.Name_EN,OP.Name) WHEN 'VN' THEN  COALESCE(OP.Name_VN,OP.Name) WHEN 'CH' THEN COALESCE(OP.Name_CH,OP.Name)  WHEN 'JP' THEN COALESCE(OP.Name_JP,OP.Name) ELSE OP.Name END AS RegPositionName,
	CASE LanguageSign WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS RegDepartName,
	CONVERT(text, BC.RegDate, 120) as RegDateToString,
	B.ViewMode,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY BC.RootId DESC ,BC.ContentNo ASC) AS RowNumber
	FROM BOARD_CONTENTS BC
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	LEFT JOIN Organization_Users OU ON OU.UserNo = BC.RegUserNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo = BC.RegPositionNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo = BC.RegDepartNO
	WHERE (BC.BoardNo=board_getprenextcontent.boardno OR   (BoardNo =0 AND B.ViewMode>=2)) AND BC.Enabled = TRUE
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getprenextcontent.userno  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1))


) ,
Total AS (Select count(*) as ToTal FROM TMP)


SELECT T.ContentNo,T.Title,T.ModUserName,T.BoardName,T.RegDateToString,FALSE AS Type,T.Private,T.ViewMode
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
WHERE (T.IsShareAll = TRUE OR IsAdmin = TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
T.RowNumber=(SELECT RowNumber-1 FROM TMP WHERE ContentNo=board_getprenextcontent.contentno)
UNION
SELECT T.ContentNo,T.Title,T.ModUserName,T.BoardName,T.RegDateToString,TRUE AS Type,T.Private,T.ViewMode
FROM TMP T
LEFT JOIN PERMISSION P ON P.ItemNo=T.ContentNo
LEFT JOIN SHARE S ON S.ContentNo=T.ContentNo
WHERE (T.IsShareAll = TRUE OR IsAdmin = TRUE OR P.AllowAccessNo IS NOT NULL OR S.ContentNo IS NOT NULL ) AND
T.RowNumber=(SELECT RowNumber+1 FROM TMP WHERE ContentNo=board_getprenextcontent.contentno);

	----SET IsAdmin = TRUE
	--declare tempTable table(
	--Type char(1),
	--ContentNo bigint,
	--BoardNo int,
	--BoardName nvarchar(200),
	--ModUserNo int,
	--ModUserName nvarchar(200),
	--ModPositionNo int,
	--ModPositionName nvarchar(200),
	--ModDepartNo int,
	--ModDepartName nvarchar(200),
	--RegDate datetime,
	--RegUserNo int,
	--Title nvarchar(500),
	--TitleEffect int,
	--GroupNo bigint,
	--Depth int,
	--OrderNo int,
	--HeadNo int,
	--IsNotice bit,
	--IsFile bit,
	--FileCount int,
	--ReplyCount int,
	--RecommendedCount int,
	--ViewedCount int,
	--HeadName nvarchar(200),
	--IsRecommended bit,
	--IsAlarm bit,
	--ReadCount int
	--)

	----not admin :
	--if(IsAdmin = FALSE) begin
