-- OBJECT ROUTINE public/dbo.board_getsettingcommunitywidget
CREATE OR REPLACE FUNCTION public.board_getsettingcommunitywidget(langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN



	RETURN QUERY
	SELECT B.BoardNo,B.ModUserNo, B.ModDate,
		COALESCE(CASE WHEN STRPOS(B.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(B.Name)  WHERE B.NAME=board_getsettingcommunitywidget.langcode),(SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME='KO')) ELSE B.Name END,'') AS Name
		, B.Description, B.FolderNo, B.DisplayTypeNo,
		B.SortNo, B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount,B.ViewMode, B.Enabled,B.SpecType
	FROM Board_NewBoardWidget W
	INNER JOIN Board_Boards B ON W.BoardNo=B.BoardNo
	WHERE W.IsDelete = FALSE AND W.Type=2
	ORDER BY W.Sort DESC;
END;
$function$


