BEGIN

	RETURN QUERY
	SELECT BS.DepartNo,BS.DepartName,BS.IsChild,BS.UserNo ,U.UserID AS UserName
	FROM Board_Sharers BS
	LEFT JOIN ORGANIZATION_USERS U on U.UserNo=BS.UserNo
	WHERE ContentNo = board_getsharers.contentno;
