-- OBJECT ROUTINE public/dbo.board_getsubmenus
CREATE OR REPLACE FUNCTION public.board_getsubmenus(userno integer DEFAULT 222, isadmin boolean DEFAULT false, langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


RETURN QUERY
WITH
 DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo ,ItemType,ROW_NUMBER() OVER(PARTITION BY ItemNo,UserNo  ORDER BY ItemNo ASC) AS Rn
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE  OB.UserNo=board_getsubmenus.userno AND OB.IsDefault= TRUE
),
History AS (SELECT BH.*, ROW_NUMBER() OVER (PARTITION BY  BH.UserNo,BH.FolderNo ORDER BY HistoryFolderNo) AS RowNum FROM Board_HistoryFolder BH WHERE BH.UserNo=board_getsubmenus.userno),
FOLDER AS (
	SELECT BF.Name,BF.FolderNo ,BF.ModUserNo,BF.ModDate, BF.Name AS JsonName, BF.ParentNo, BF.SortNo,TRUE AS IsFolder , 0 AS CountContent, 0 AS ViewMode ,COALESCE(BH.IsOpen,1) AS IsOpen
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_getsubmenus.userno
	LEFT JOIN History BH ON  BF.FolderNo=BH.FolderNo AND BH.RowNum=1
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BF.FolderNo AND D.ItemType=1
	WHERE   BF.Enabled = TRUE AND (IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0 OR D.AllowValue>0 )
	ORDER BY SortNo ASC,BF.FolderNo ASC),
BOARD AS (
	SELECT B.BoardNo, B.ModUserNo, B.ModDate, B.Name, B.Description, B.FolderNo, B.DisplayTypeNo, B.SortNo,
				B.IsReply, B.IsHead, B.IsNotice, B.IsRecommend, B.RecommendedDisplayCount, B.Enabled,B.ViewMode,B.SpecType,
				(SELECT COUNT(*) FROM Board_Contents BC
				WHERE '2020-12-31'::timestamp< BC.RegDate AND (BC.BoardNo = B.BoardNo
					AND BC.Enabled = TRUE
					And BC.RegUserNo <> board_getsubmenus.userno
					And BC.ContentNo Not In (Select BV.ContentNo From Board_ViewedLogs BV where BV.UserNo=board_getsubmenus.userno)
					And (IsAdmin = TRUE OR BA.AllowValue=7 OR D.AllowValue=7 OR
					(  (BC.BoardNo IN (SELECT * FROM public."Board_GetBoardAllow"(UserNo ,2)) OR B.SpecType=1)
						AND (
							(BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN public."Organization_BelongToDepartment" DP ON DP.DepartNo= BS1.DepartNo AND DP.UserNo=board_getsubmenus.userno)) -- SHARE BY DEPARTMENT
						  OR(BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1 where BSS1.contentno=BC.ContentNo and BSS1.userno=board_getsubmenus.userno)) -- SHARE BY USER
						  OR BC.IsShareAll = TRUE  -- SHARE ALL
							) )
					))
				 ) As CountContent
			FROM Board_Boards B
			--INNER JOIN FOLDER F ON F.FolderNo=B.FolderNo
			LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_getsubmenus.userno
			LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo AND D.ItemType=2 AND Rn=1
			WHERE  B.Enabled = TRUE  AND (IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL OR D.AllowValue IS NOT NULL)
			--ORDER BY SortNo ASC
),
TREESUB AS
(
    SELECT    	COALESCE(CASE WHEN STRPOS(T.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(T.Name)  WHERE NAME=board_getsubmenus.langcode),(SELECT StringValue FROM ParseJson(T.Name)  WHERE NAME='KO')) ELSE T.Name END,'') AS Name ,
	 ('f' || CAST(T.FolderNo AS VARCHAR))AS Id  ,
	 T.ModUserNo,T.ModDate, T.Name AS JsonName,
	CASE  WHEN T.ParentNo = 0 THEN '#' ELSE 'f' || CAST(T.ParentNo AS VARCHAR)  END AS ParentNo,
	T.SortNo,TRUE AS IsFolder ,T.IsOpen , 0 AS CountContent, 0 AS ViewMode, 'fa fa-folder' AS icon
    FROM       FOLDER T
    UNION ALL
	SELECT	COALESCE(CASE WHEN STRPOS(B.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_getsubmenus.langcode),(SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME='KO')) ELSE B.Name END,'') AS Name ,
		('b' || CAST(B.BoardNo AS VARCHAR) )  AS Id  ,
		B.ModUserNo,B.ModDate, B.Name AS JsonName,
		CASE WHEN B.FolderNo = 0 THEN '#' ELSE 'f' || CAST(B.FolderNo AS VARCHAR)   END  AS ParentNo,
		B.SortNo,FALSE AS IsFolder ,FALSE AS IsOpen,B.CountContent,B.ViewMode, 'fa fa-file-o' AS icon
	 FROM      BOARD B
)
SELECT F.id,F.ParentNo AS parent, F.Name+ CASE
    WHEN ViewMode > 0 THEN ' <span class="submenu_board_content_count">' || CAST(ViewMode AS VARCHAR) + '</span>'
    ELSE ''
  END AS text,f.icon,
  '{ "type": "' || CAST(F.ViewMode AS varchar) + '", "RegUserNo": "' || CAST( F.ModUserNo AS varchar) + '" }' AS li_attr,
    '{ "title": "' || F.Name || '", "jsonName": "' || F.JsonName || '" }' AS data,
	 '{ "opened": "' || CASE  WHEN F.IsOpen = TRUE THEN 'true'  ELSE 'false' END || '", "selected": "'+ 'false'  + '" }' AS state
FROM TREESUB F
ORDER BY ParentNo ASC, SortNo DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getteamlist
CREATE OR REPLACE FUNCTION public.board_getteamlist(departno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH RECURSIVE TEMP AS (
	SELECT T.DepartNo,T.Name
	FROM  Organization_Departments T Where T.ParentNo=board_getteamlist.departno AND T.Enabled = TRUE
	UNION  ALL
	SELECT  D.DepartNo,D.Name
	FROM  Organization_Departments D
	INNER JOIN  TEMP P ON P.DepartNo=D.ParentNo  AND D.Enabled = TRUE

)
SELECT  *
FROM  TEMP;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getteamname
CREATE OR REPLACE FUNCTION public.board_getteamname(teamno character varying DEFAULT 'O&M'::character varying, companyno character varying DEFAULT 'JN1'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    num integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


SELECT COUNT(*) INTO num FROM Board_Contents C
INNER JOIN Board_Boards B ON B.BoardNo=C.BoardNo
Where B.ViewMode=76 And C.BadNo =board_getteamname.teamno AND C.DesignNo=board_getteamname.companyno AND YEAR(C.RegDate) =YEAR(NOW()) AND C.Enabled = TRUE;
RETURN QUERY
SELECT CompanyNo || '-' || CAST(YEAR(NOW()) AS nvarchar) +'-' || TeamNo || '-' || CAST(REPLICATE('0',5-LEN(RTRIM(Num+1))) + RTRIM(Num+1) AS nvarchar);
END;
$function$


-- OBJECT ROUTINE public/dbo.board_gettreeboard
CREATE OR REPLACE FUNCTION public.board_gettreeboard(isdisabled boolean DEFAULT true, langcode character varying DEFAULT 'EN'::character varying, userno integer DEFAULT 70, isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


RETURN QUERY
WITH
 DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo ,ItemType
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE  OB.UserNo=board_gettreeboard.userno AND OB.IsDefault= TRUE
),
PARENTS AS (
	SELECT BF.*
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_gettreeboard.userno
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BF.FolderNo AND D.ItemType=1
	WHERE  BF.ParentNo = 0 AND  BF.Enabled = TRUE AND (IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue IS NOT NULL  OR D.AllowValue IS NOT NULL)
	ORDER BY SortNo ASC,FolderNo ASC),
CHILDRENTS AS (
	SELECT BF.*
	FROM  Board_Folders BF
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 AND BA.UserNo=board_gettreeboard.userno
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BF.FolderNo AND D.ItemType=1
	WHERE  BF.ParentNo >0 AND  BF.Enabled = TRUE  AND (IsAdmin = TRUE OR BF.SpecType=1 OR BA.AllowValue IS NOT NULL  OR D.AllowValue IS NOT NULL)
	ORDER BY SortNo ASC,FolderNo ASC),
BOARDCHILD AS (
	SELECT B.*
	FROM Board_Boards B
	LEFT JOIN Board_AllowAccess BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2 AND BA.UserNo=board_gettreeboard.userno
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo AND D.ItemType=2
	WHERE  B.Enabled = TRUE  AND (IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL  OR D.AllowValue IS NOT NULL)
),
FOLDER AS
(
    SELECT     T.FolderNo as No ,T.Name,T.ParentNo, FALSE as IsBoard,T.SortNo as RootTree,1 as Index,T.SortNo,0 AS ViewMode
    FROM       PARENTS T
    UNION ALL
    SELECT     C.FolderNo as No,C.Name,C.ParentNo, FALSE as IsBoard,F.RootTree,(F.Index + 1) AS Index,C.SortNo,0 AS ViewMode
    FROM       CHILDRENTS C
    INNER JOIN FOLDER F ON F.No = C.ParentNo AND C.Enabled=board_gettreeboard.isdisabled AND F.IsBoard = FALSE
	UNION ALL
	SELECT B.BoardNo as No ,B.Name,B.FolderNo as ParentNo,TRUE as IsBoard ,F.RootTree,(F.Index + 1) AS Index,B.SortNo,B.ViewMode AS ViewMode
	FROM BOARDCHILD B
	INNER JOIN FOLDER F on F.No= B.FolderNo AND B.Enabled=board_gettreeboard.isdisabled AND F.IsBoard = FALSE
), TEMP AS (
	SELECT RootTree, MAX(Index) AS LastRoot
	FROM FOLDER
	GROUP BY RootTree
)
SELECT	F.No ,
		--F.Name ,
		COALESCE(CASE WHEN STRPOS(F.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(F.Name)  WHERE F.NAME=board_gettreeboard.langcode),(SELECT StringValue FROM ParseJson(F.Name)  WHERE NAME='KO')) ELSE F.Name END,'') AS Name ,
		F.ParentNo ,
		F.IsBoard ,
		F.RootTree ,
		F.Index ,
		Cast((CASE WHEN T.LastRoot IS NULL THEN 0 ELSE 1 END) AS BIT) AS IsLastRoot ,
		F.ViewMode
	FROM FOLDER F
	LEFT JOIN TEMP T ON T.RootTree=F.RootTree And T.LastRoot=F.Index
	ORDER BY  ParentNo ASC,--IsBoard DESC,
	F.SortNo DESC; --,F.No ASC
END;
$function$


-- OBJECT ROUTINE public/dbo.board_gettreesubmenu
CREATE OR REPLACE FUNCTION public.board_gettreesubmenu(userno integer DEFAULT 222, isadmin boolean DEFAULT false, langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH RECURSIVE DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo ,ItemType,ROW_NUMBER() OVER(PARTITION BY ItemNo,UserNo,ItemType  ORDER BY ItemNo ASC) AS Rn
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE  OB.UserNo=board_gettreesubmenu.userno AND OB.IsDefault= TRUE
),
History AS (SELECT BH.*, ROW_NUMBER() OVER (PARTITION BY  BH.UserNo,BH.FolderNo ORDER BY HistoryFolderNo) AS RowNum FROM Board_HistoryFolder BH WHERE BH.UserNo=board_gettreesubmenu.userno),
PERMISSION AS (
        SELECT ItemNo, ItemType, MAX(AllowValue) AS AllowValue
        FROM (
            SELECT ItemNo, ItemType, AllowValue
            FROM Board_AllowAccess
            WHERE UserNo = board_gettreesubmenu.userno

            UNION ALL

            SELECT ItemNo, ItemType, AllowValue
            FROM DEPARTPERMISSION
            WHERE rn = 1
        ) P
        GROUP BY ItemNo, ItemType
    ),

FOLDER AS (
	SELECT BF.FolderNo,
            BF.ParentNo,
            BF.Name,
            BF.SortNo,
            BF.ModUserNo,
            BF.ModDate,
            COALESCE(BH.IsOpen,1) AS IsOpen
	FROM  Board_Folders BF
	LEFT JOIN PERMISSION BA ON BA.ItemNo=BF.FolderNo AND BA.ItemType=1 --AND BA.UserNo=UserNo
	LEFT JOIN History BH ON  BF.FolderNo=BH.FolderNo AND BH.RowNum=1
	--LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BF.FolderNo AND D.ItemType=1
	WHERE   BF.Enabled = TRUE AND (IsAdmin = TRUE OR BF.SpecType=1  OR BA.AllowValue>0-- OR D.AllowValue>0
	)
	ORDER BY SortNo ASC,FolderNo ASC),
	    CONTENT_COUNT AS (
        SELECT
            BC.BoardNo,
            COUNT(*) AS CountContent
        FROM Board_Contents BC
        WHERE
            BC.Enabled = TRUE
            AND BC.RegDate > '2020-12-31'
            AND BC.RegUserNo <> board_gettreesubmenu.userno
            AND NOT EXISTS (
                SELECT 1
                FROM Board_ViewedLogs BV
                WHERE BV.ContentNo = BC.ContentNo
                  AND BV.UserNo = board_gettreesubmenu.userno
            )
        GROUP BY BC.BoardNo
    ),
BOARD AS (
	SELECT  B.BoardNo,
            B.FolderNo,
            B.Name,
            B.SortNo,
            B.ModUserNo,
            B.ModDate,
            B.ViewMode,
				(SELECT COUNT(*) FROM Board_Contents BC
				WHERE '2020-12-31'::timestamp< BC.RegDate AND (BC.BoardNo = B.BoardNo
					AND BC.Enabled = TRUE
					And BC.RegUserNo <> board_gettreesubmenu.userno
					And BC.ContentNo Not In (Select BV.ContentNo From Board_ViewedLogs BV where BV.UserNo=board_gettreesubmenu.userno)
					And (IsAdmin = TRUE OR BA.AllowValue=7  OR
					(  (BC.BoardNo IN (SELECT * FROM public."Board_GetBoardAllow"(UserNo ,2)) OR B.SpecType=1)
						AND (
							(BC.ContentNo IN (SELECT BS1.ContentNo FROM Board_Sharers BS1 INNER JOIN public."Organization_BelongToDepartment" DP ON DP.DepartNo= BS1.DepartNo AND DP.UserNo=board_gettreesubmenu.userno)) -- SHARE BY DEPARTMENT
						  OR(BC.ContentNo IN ( SELECT BSS1.ContentNo FROM Board_Sharers BSS1 where BSS1.contentno=BC.ContentNo and BSS1.userno=board_gettreesubmenu.userno)) -- SHARE BY USER
						  OR BC.IsShareAll = TRUE  -- SHARE ALL
							) )
					))
				 ) As CountContent
			FROM Board_Boards B
			--INNER JOIN FOLDER F ON F.FolderNo=B.FolderNo
			LEFT JOIN PERMISSION BA ON BA.ItemNo=B.BoardNo AND BA.ItemType=2-- AND BA.UserNo=UserNo
			--LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=B.BoardNo AND D.ItemType=2 AND Rn=1
			WHERE  B.Enabled = TRUE  AND (IsAdmin = TRUE OR  B.SpecType=1 OR BA.AllowValue IS NOT NULL )
			--ORDER BY SortNo ASC
),
TREESUB AS
(
    SELECT    	COALESCE(CASE WHEN STRPOS(T.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(T.Name)  WHERE NAME=board_gettreesubmenu.langcode),(SELECT StringValue FROM ParseJson(T.Name)  WHERE NAME='KO')) ELSE T.Name END,'') AS Name ,
	T.FolderNo AS No  ,T.ModUserNo,T.ModDate, T.Name AS JsonName, T.ParentNo, T.SortNo,TRUE AS IsFolder ,T.IsOpen , 0 AS CountContent, 0 AS ViewMode
    FROM       FOLDER T
    UNION ALL
	SELECT	COALESCE(CASE WHEN STRPOS(B.Name, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME=board_gettreesubmenu.langcode),(SELECT StringValue FROM ParseJson(B.Name)  WHERE NAME='KO')) ELSE B.Name END,'') AS Name ,
		B.BoardNo AS No  ,B.ModUserNo,B.ModDate, B.Name AS JsonName, B.FolderNo AS ParentNo, B.SortNo,FALSE AS IsFolder ,FALSE AS IsOpen,B.CountContent,B.ViewMode
	 FROM      BOARD B
)
SELECT F.* --,   ROW_NUMBER() OVER (PARTITION BY No,IsFolder ORDER BY ParentNo ASC, SortNo DESC) AS rn
FROM TREESUB F
ORDER BY ParentNo ASC, SortNo DESC;
  --SET NOCOUNT ON;

  --  -- 1. Optimized Permission CTE
  --  WITH DEPARTPERMISSION AS (
  --      SELECT ItemNo, ItemType, MAX(AllowValue) AS AllowValue
  --      FROM Board_DepartAllowAccess BD
  --      INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo = BD.DepartNo
  --      WHERE OB.UserNo = UserNo AND OB.IsDefault = TRUE
  --      GROUP BY ItemNo, ItemType
  --  ),

  --  -- 2. History CTE (Get only the latest state)
  --  History AS (
