-- OBJECT ROUTINE public/dbo.board_getviewedlogs
CREATE OR REPLACE FUNCTION public.board_getviewedlogs(contentno bigint DEFAULT 827)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH SHARE AS(
		SELECT U.UserNo ,BS.ContentNo
		FROM Board_Sharers BS
		INNER JOIN (
			SELECT U.UserNo,OP.DepartNo
			FROM Organization_Users U
			INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
			WHERE U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
		WHERE BS.ContentNo=board_getviewedlogs.contentno
	)
	SELECT BV.LogNo, BV.BoardNo, BV.ContentNo, BV.UserNo, BV.UserName, BV.PositionNo,COALESCE(OP.Name,'') AS PositionName, BV.DepartNo,COALESCE(OD.Name,'') AS DepartName,
		BV.ViewedDate, BV.ClientIP,OU.MailAddress,OU.UserPhoto,OU.Photo
	FROM Board_ViewedLogs BV
	INNER JOIN Board_Contents BC ON BV.ContentNo=BC.ContentNo AND BC.ContentNo=board_getviewedlogs.contentno
	LEFT JOIN Board_Boards BB ON BB.BoardNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.UserNo=BV.UserNo
	INNER JOIN Organization_Users OU ON BV.UserNo=OU.UserNo
	LEFT JOIN Organization_Departments OD ON OD.DepartNo=BV.DepartNo
	LEFT JOIN Organization_Positions OP ON OP.PositionNo=BV.PositionNo
	WHERE   BB.SpecType=1 OR BV.ContentNo = board_getviewedlogs.contentno AND (BC.IsShareAll=TRUE OR COALESCE(S.ContentNo,0)!=0 OR BV.UserNo=BC.RegUserNo)
	ORDER BY ViewedDate ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_getwidgetcarousel
CREATE OR REPLACE FUNCTION public.board_getwidgetcarousel(userno integer DEFAULT 70, curentpage integer DEFAULT 1, pagesize integer DEFAULT 10, isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH PERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_AllowAccess
	WHERE ItemType=2 AND UserNo=board_getwidgetcarousel.userno
),DEPARTPERMISSION AS (
	Select ItemNo ,AllowValue,AllowAccessNo
	FROM Board_DepartAllowAccess BD
	INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
	WHERE BD.ItemType=2 AND OB.UserNo=board_getwidgetcarousel.userno AND OB.IsDefault= TRUE
),
SHARE AS(
	SELECT U.UserNo ,BS.ContentNo
	FROM Board_Sharers BS
	INNER JOIN (
		SELECT U.UserNo,OP.DepartNo
		FROM Organization_Users U
		INNER JOIN Organization_BelongToDepartment OP ON OP.UserNo=U.UserNo
		WHERE U.UserNo=board_getwidgetcarousel.userno AND U.Enabled = TRUE
		) U ON U.UserNo=BS.UserNo OR U.DepartNo=BS.DepartNo
),
TMP AS (
	SELECT BC.BoardNo,BC.ContentNo,BC.Title,BC.RegDate,
	ROW_NUMBER() OVER(PARTITION BY BC.Enabled  ORDER BY  BC.RootId  DESC) AS RowNumber
	FROM BOARD_CONTENTS BC
	INNER JOIN Board_NewBoardWidget W ON BC.BoardNo= W.BoardNo AND W.Type=1 AND W.IsDelete = FALSE
	LEFT JOIN Board_Boards B ON B.BoardNo=BC.BoardNo
	LEFT JOIN PERMISSION P ON P.ItemNo=BC.BoardNo
	LEFT JOIN DEPARTPERMISSION D ON D.ItemNo=BC.BoardNo
	LEFT JOIN SHARE S ON S.ContentNo=BC.ContentNo
	WHERE B.ViewMode=1
	AND BC.Enabled = TRUE
	AND ( IsAdmin = TRUE OR BC.RegUserNo=board_getwidgetcarousel.userno  OR P.AllowValue=7 OR  D.AllowValue=7 OR ((P.AllowAccessNo IS NOT NULL OR D.AllowAccessNo IS NOT NULL)AND B.SpecType=0 AND (BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL)) OR ((BC.IsShareAll = TRUE  OR S.ContentNo IS NOT NULL) AND  B.SpecType=1)
)
)
SELECT T.BoardNo,
T.ContentNo ,
T.Title,
F.Url AS FileUrl,
REPLACE(REPLACE(F.Url, '/Attach/', '/Thumbnail/'),'/File/','/Thumbnail/') AS ThumbnailFileUrl
FROM TMP T
LEFT JOIN (SELECT ContentNo,Url,ROW_NUMBER() OVER(PARTITION BY ContentNo  ORDER BY ContentNo ASC) AS Rn FROM Board_Files ) F ON F.ContentNo=T.ContentNo AND F.Rn=1
WHERE   T.RowNumber>(CurentPage-1)*PageSize AND T.RowNumber<=board_getwidgetcarousel.curentpage*PageSize
ORDER BY T.RowNumber;
END;
$function$


-- OBJECT ROUTINE public/dbo.board_insertandroiddevice
CREATE OR REPLACE FUNCTION public.board_insertandroiddevice(userno integer, regdate timestamp without time zone, deviceid character varying, osversion character varying, notificationoptions character varying, timezoneoffset integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    deviceno bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	DELETE FROM Board_AndroidDevices WHERE UserNo = board_insertandroiddevice.userno OR DeviceID = board_insertandroiddevice.deviceid;

	INSERT INTO Board_AndroidDevices (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset)
	VALUES (UserNo, RegDate, DeviceID, OSVersion, NotificationOptions, TimezoneOffset);


