-- OBJECT ROUTINE public/dbo.board_insertfile
CREATE OR REPLACE FUNCTION public.board_insertfile(contentno bigint DEFAULT 5785, name character varying DEFAULT '2023-T5-2X(VN-SB)(9).pdf'::character varying, size integer DEFAULT 107432, filepath character varying DEFAULT '/_Repository/_Board/Attach/5785/2023-T5-2X(VN-SB)(9).pdf'::character varying, sort integer DEFAULT 0)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    fileno bigint;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


