	UPDATE BW SET Sort=(SELECT /* /* TOP 1 */ */ T.Sort FROM WidgetTemp T WHERE BW.No <>T.No),ModUserNo= board_upwidget.userno,ModDate=NOW()
	FROM Board_NewBoardWidget BW
	INNER JOIN WidgetTemp T ON T.No=BW.No;
END;
