-- OBJECT ROUTINE public/dbo.bslg_getcmtinfo
CREATE OR REPLACE FUNCTION public.bslg_getcmtinfo(targetid character varying, langindex character varying, orgcd character varying, startdate character varying, enddate character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	
	RETURN QUERY
	select ID
		, Content
		, TargetID
		, WriterID
		, RegDate
		, Status 
		, U.Name as UserName
		, WriterDate 
		, D.Name as OrgNm
		, P.Name as PosNm
	from BSLG_Comment C
	INNER JOIN Organization_Users U on C.WriterID = U.UserID
	INNER JOIN Organization_BelongToDepartment B on B.UserNo = U.UserNo and B.IsDefault = TRUE
	INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
	INNER JOIN Organization_Positions P ON P.PositionNo = B.PositionNo
	WHERE C.Status = Flag AND C.TargetID = bslg_getcmtinfo.targetid
	AND ( RegDate >= bslg_getcmtinfo.startdate AND RegDate <= bslg_getcmtinfo.enddate);
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getcmtinfo_departno
CREATE OR REPLACE FUNCTION public.bslg_getcmtinfo_departno(langindex character varying, orgcd character varying, startdate character varying, enddate character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	
	RETURN QUERY
	select ID
		, Content
		, TargetID
		, WriterID
		, RegDate
		, Status 
		, U.Name as UserName
		, WriterDate 
		, D.Name as OrgNm
		, P.Name as PosNm
	from BSLG_Comment C
	INNER JOIN Organization_Users U on C.WriterID = U.UserID
	INNER JOIN Organization_BelongToDepartment B on B.UserNo = U.UserNo and B.IsDefault = TRUE
	INNER JOIN Organization_Departments D ON D.DepartNo = B.DepartNo
	INNER JOIN Organization_Positions P ON P.PositionNo = B.PositionNo
	WHERE C.Status = Flag AND C.orgcd = bslg_getcmtinfo_departno.orgcd
	AND ( RegDate >= bslg_getcmtinfo_departno.startdate AND RegDate <= bslg_getcmtinfo_departno.enddate);
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getdeptcount
CREATE OR REPLACE FUNCTION public.bslg_getdeptcount(userid character varying, deptid character varying, sdate character varying, edate character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	

			RETURN QUERY
			SELECT	COUNT(A.UserID)
			FROM	BSLG_Log A
			inner join CMONUsers B
			on A.UserID = B.UserId
			inner join CMONOrgan C
			on B.OrgCd1 = C.OrgCd
			inner join CMONCommCd D
			on B.PosFg1 = D.commcd
			where
			(RegDate >= bslg_getdeptcount.sdate AND RegDate <=  bslg_getdeptcount.edate )
			AND		Plot is null 
			AND		B.UseYn = 'Y'
			AND		C.OrgCd = bslg_getdeptcount.deptid
			AND		D.ClassCd = 'C001'
			
			group by D.Commcd,A.UserID;
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getdeptuser
CREATE OR REPLACE FUNCTION public.bslg_getdeptuser(deptid character varying, lang character varying DEFAULT '1'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
--declare Deptid int
--set Deptid=1081

RETURN QUERY
select userid, 
 case when orgcd1=bslg_getdeptuser.deptid then posfg1  
	  when orgcd2=bslg_getdeptuser.deptid then posfg2
	  when orgcd3=bslg_getdeptuser.deptid then posfg3
	  when orgcd4=bslg_getdeptuser.deptid then posfg4
	  when orgcd5=bslg_getdeptuser.deptid then posfg5
	  when orgcd6=bslg_getdeptuser.deptid then posfg6
	  when orgcd7=bslg_getdeptuser.deptid then posfg7
 end as posfg,
 CASE Lang 
			WHEN '1' THEN UserNm1 
			WHEN '2' THEN CASE UserNm2 WHEN '' THEN UserNm2 ELSE UserNm2 END
			WHEN '3' THEN CASE UserNm3 WHEN '' THEN UserNm2 ELSE UserNm3 END
			WHEN '4' THEN CASE UserNm4 WHEN '' THEN UserNm2 ELSE UserNm4 END
			ELSE UserNm1
   End AS UserNm
  ,Deptid AS OrgCd
 from CMONUsers   A  
 LEFT OUTER JOIN CMONCommCd B   
 ON A.PosFg1 = B.CommCd AND B.ClassCd = 'C001'
where A.UseYn='Y' and (orgcd1=bslg_getdeptuser.deptid or orgcd2=bslg_getdeptuser.deptid or orgcd3=bslg_getdeptuser.deptid or orgcd4=bslg_getdeptuser.deptid or orgcd5=bslg_getdeptuser.deptid or orgcd6=bslg_getdeptuser.deptid or orgcd7=bslg_getdeptuser.deptid)
order by  B.SortOrd, A.UserGrade, A.RegYmd,UserNm;
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getdiarylog
CREATE OR REPLACE FUNCTION public.bslg_getdiarylog(userid character varying, startdate character varying, enddate character varying, searchtext character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT UserID,RegDate,Content1, Content2, att1, att2, att3, att4, att5 
	FROM BSLG_Log WHERE UserID=bslg_getdiarylog.userid 
	AND Plot = 'Diary'
	AND  Content1 ILIKE '%' || SearchText || '%'
	AND ( RegDate >= bslg_getdiarylog.startdate AND RegDate <= bslg_getdiarylog.enddate) ORDER BY RegDate;
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getdwlog
CREATE OR REPLACE FUNCTION public.bslg_getdwlog(userid character varying, sdate character varying, edate character varying, searchtext character varying, orgcd character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	RETURN QUERY
	SELECT UserID,RegDate,Content1, Content2, att1, att2, att3, att4, att5 
	FROM BSLG_Log WHERE Orgcd =bslg_getdwlog.orgcd 
	AND (Plot = '' or Plot is null)
	AND  Content1 ILIKE '%' || SearchText || '%'
	AND ( RegDate >= bslg_getdwlog.sdate AND RegDate <= bslg_getdwlog.edate) ORDER BY RegDate;
END;
$function$


