-- OBJECT ROUTINE public/dbo.bslg_getorgs
CREATE OR REPLACE FUNCTION public.bslg_getorgs(userid character varying, orgcd character varying, useyn character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

   
    RETURN QUERY
    select 
  UserId
 , CASE Lang   
   WHEN '1' THEN UserNm1   
   WHEN '2' THEN CASE UserNm2 WHEN '' THEN UserNm2 ELSE UserNm2 END  
   WHEN '3' THEN CASE UserNm3 WHEN '' THEN UserNm2 ELSE UserNm3 END  
   WHEN '4' THEN CASE UserNm4 WHEN '' THEN UserNm2 ELSE UserNm4 END  
   ELSE UserNm1  
   End AS UserNm  
 , OrgCd1   as OrgCd  
 , PosFg1   as PosFg  
 , GradeFg1  as GradeFg  
 from CMONUsers 
 where UseYn = 'Y' AND (
  OrgCd1 =bslg_getorgs.orgcd 
  OR OrgCd2 =bslg_getorgs.orgcd
  OR OrgCd3 =bslg_getorgs.orgcd 
  OR OrgCd4 =bslg_getorgs.orgcd 
  OR OrgCd5 =bslg_getorgs.orgcd 
  OR OrgCd6 =bslg_getorgs.orgcd
  OR OrgCd7 =bslg_getorgs.orgcd);
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getread
CREATE OR REPLACE FUNCTION public.bslg_getread(regid character varying, regdate character varying, lang character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	
	RETURN QUERY
	SELECT 
		(SELECT CASE Lang WHEN '1' THEN cu.UserNm1
							 WHEN '2' THEN cu.UserNm2
							 WHEN '3' THEN cu.UserNm3 
							 WHEN '4' THEN cu.UserNm4
				  ELSE UserNm1 
				  END as UserNm
			FROM CMONUsers cu WHERE cu.UserID = ReaderId ) as ReadNm
		, (SELECT public."CMONGetCommCdNm"('C001', cu.PosFg1, Lang) FROM CMONUsers cu WHERE cu.UserID = ReaderId) as PosNm
		, (SELECT public."CMONGetOrganNm"(cu.OrgCd1, Lang)  FROM CMONUsers cu WHERE cu.UserID = ReaderId) as OrgNm
		, ReadDate
	FROM BSLG_Reader
	WHERE RegId = bslg_getread.regid
	AND   RegDate = bslg_getread.regdate;
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getschmlog
CREATE OR REPLACE FUNCTION public.bslg_getschmlog(userid character varying, date character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT SM.Seq, Title, Content, Writer, OpenType, Divide, Kind, smsYN,  smsSDate, StartDate, StartTime, LMonth, EndDate, LWeekSeq, EndTime,  LWeek, LDaily
	FROM schmmaster SM 
	WHERE EndDate >= bslg_getschmlog.date and StartDate <= bslg_getschmlog.date and  Divide ILIKE '%S%' AND Writer = bslg_getschmlog.userid
	Order by StartTime;
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_getwlog
