-- OBJECT ROUTINE public/dbo.bslg_loworg
CREATE OR REPLACE FUNCTION public.bslg_loworg(orgcd character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
select	b.orgnm1, b.orgcd
from	cmongroup a 
		inner join cmonorgan b 
		on b.parentorgcd = bslg_loworg.orgcd
where	grpcd = substring(b.orgpath,1,4);
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_loworgcount
CREATE OR REPLACE FUNCTION public.bslg_loworgcount(orgcd character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
select	count(a.grpnm1) as cut
from	cmongroup a 
		inner join cmonorgan b 
		on b.parentorgcd = bslg_loworgcount.orgcd
where	grpcd = substring(b.orgpath,1,4);
END;
$function$


-- OBJECT ROUTINE public/dbo.bslg_org
CREATE OR REPLACE FUNCTION public.bslg_org(userid character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
select	a.grpcd, a.grpnm1, b.orgcd, b.orgnm1, b.parentorgcd, b.orgpath, c.userid, c.usernm1, c.orgcd1
from	cmongroup a 
		inner join cmonorgan b 
		on a.grpcd = substring(b.orgpath, 1, 4)
		inner join cmonusers c
		on b.orgcd = c.orgcd1
where	userid = bslg_org.userid;
END;
$function$


