 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	SELECT FilterNo, ClientIP, Allow, SortNo
	FROM Center_IPFilters
	ORDER BY SortNo ASC;
END;
$function$


-- OBJECT ROUTINE public/dbo.center_getipfiltersforapplication
