-- OBJECT ROUTINE public/dbo.center_getservice_notificationservice
CREATE OR REPLACE FUNCTION public.center_getservice_notificationservice()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	select 
	NotificationNo
	,CompanyNo
	,ProjectCode
	,Connectionkey
	,SendUserNo
	,RecipientUserNo
	,RecipientDepartNo
	,StartDate
	,EndDate
	,RepeatType
	,RepeatOptions
	,COALESCE(State,0) as State
	,Execution
	,CrewChatRoomNo
	from Center_NotificationService
	where COALESCE(State,0) = 0
	order by NotificationNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.center_getservice_notificationservice_alarmdetail
CREATE OR REPLACE FUNCTION public.center_getservice_notificationservice_alarmdetail(notificationno bigint, requestday date)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	select A.*,B.ExecutionDate from Center_NotificationService_AlarmDetail A
	left join Center_NotificationService_AlarmDetail_Execution B
	on A.NotificationService_AlarmDetailNo = B.NotificationService_AlarmDetailNo
	and B.ExecutionDate = center_getservice_notificationservice_alarmdetail.requestday
	where A.NotificationNo = center_getservice_notificationservice_alarmdetail.notificationno;
END;
$function$


