-- OBJECT ROUTINE public/dbo.center_getuserall_notificationservice
CREATE OR REPLACE FUNCTION public.center_getuserall_notificationservice()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	select A.UserNo,A.UserID,A.Name,A.Password,A.MailAddress from Organization_Users A
	join Organization_BelongToDepartment B
	on A.UserNo = B.UserNo 
	where A.Enabled = TRUE and UserID != 'crewnotifer' and B.IsDefault = TRUE;
END;
$function$


-- OBJECT ROUTINE public/dbo.center_getuserfailedloginlist
CREATE OR REPLACE FUNCTION public.center_getuserfailedloginlist()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	select UserNo,UserID,Name,FailedLoginCount from Organization_Users
	where FailedLoginCount >= (select Value from Center_Configuration where key = 'KEY_Use_LOGIN_PasswordMust_Cnt');
END;
$function$


