-- OBJECT ROUTINE public/dbo.contacts_checkgroup
CREATE OR REPLACE FUNCTION public.contacts_checkgroup(reguserno integer, type integer, value character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	-- 그룹번호로 체크
	IF Type = 0 THEN
		RETURN QUERY
		SELECT GroupNo FROM ContactsGroup
		WHERE RegUserNo=contacts_checkgroup.reguserno
		AND GroupNo=contacts_checkgroup.value
		AND UseYn='Y';
	-- 그룹이름으로 체크
