-- OBJECT ROUTINE public/dbo.contacts_deletedepartallowaccess
CREATE OR REPLACE FUNCTION public.contacts_deletedepartallowaccess(listallowaccessno character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    departno integer;
    itemno integer;
BEGIN


	CREATE TEMP TABLE Contact_DepartAllowAccess ON COMMIT DROP AS SELECT * FROM Contact_DepartAllowAccess
	WHERE AllowAccessNo IN(SELECT * FROM SplitString(ListAllowAccessNo,','));



	WHILE (Select Count(*) From Contact_DepartAllowAccess) > 0 LOOP
			SELECT DA.DepartNo, DA.ItemNo INTO departno, itemno FROM Contact_DepartAllowAccess DA;
			CREATE TEMP TABLE ShareGroupTemp ON COMMIT DROP AS WITH RECURSIVE ShareGroupNos AS (
				SELECT     PF.ShareGroupNo , PF.ParentNo
				FROM       Contact_ShareGroup PF

				WHERE PF.ShareGroupNo =ItemNo
				UNION ALL
				SELECT     CF.ShareGroupNo , CF.ParentNo
				FROM       Contact_ShareGroup CF
				INNER JOIN ShareGroupNos FN ON FN.ShareGroupNo = CF.ParentNo AND CF.IsDelete = FALSE
			)
			SELECT * FROM ShareGroupNos;

			DELETE FROM Contact_DepartAllowAccess WHERE DepartNo=DepartNo AND ItemNo IN (SELECT BB.ShareGroupNo FROM Contact_ShareGroup BB INNER JOIN ShareGroupTemp BF ON BF.ShareGroupNo=bb.ShareGroupNo);

			DROP TABLE IF EXISTS ShareGroupTemp;

			DELETE FROM Contact_DepartAllowAccess WHERE ItemNo=ItemNo AND  DepartNo=DepartNo;
	END LOOP;
	DROP TABLE IF EXISTS Contact_DepartAllowAccess;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_deletehistory
CREATE OR REPLACE FUNCTION public.contacts_deletehistory(historynolist character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
DECLARE
    temphistoryno integer;
    chkhistoryno character varying;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN




	HistoryNoList := contacts_deletehistory.historynolist || ',';
	ChkHistoryNo := REPLACE(HistoryNoList,',','');
	IF LEN(ChkHistoryNo) > 0 THEN

		WHILE STRPOS(HistoryNoList, ',') > 0 LOOP
			TempHistoryNo := SUBSTRING(HistoryNoList,0,STRPOS(HistoryNoList, ','));
			DELETE FROM ContactsNumberHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsEmailHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsDaysHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsCompanyHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsAddressHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsSnsHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsGroupUserHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsUserHistory WHERE HistoryNo = TempHistoryNo;

			HistoryNoList := SUBSTRING(HistoryNoList,STRPOS(HistoryNoList, ',')+1,LEN(HistoryNoList));
		END LOOP;

		IF 0 <> 0 THEN

		END IF;

	END IF;
END;
$function$


