-- OBJECT ROUTINE public/dbo.contacts_downpublicgroup
CREATE OR REPLACE FUNCTION public.contacts_downpublicgroup(userno integer DEFAULT 70, groupno integer DEFAULT 643, parentno integer DEFAULT 641)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
WITH RECURSIVE GroupTmp AS (select CG.*
from Contact_PublicGroup CG
WHERE  CG.ParentNo=contacts_downpublicgroup.parentno AND CG.IsDelete= FALSE AND CG.Sort >= (SELECT Sort FROM Contact_PublicGroup WHERE PublicGroupNo=contacts_downpublicgroup.groupno)
ORDER BY Sort ASC)
,
GroupUpdate AS(SELECT T.PublicGroupNo,T1.Sort
FROM GroupTmp T
LEFT JOIN GroupTmp T1 ON T1.PublicGroupNo <> T.PublicGroupNo)
UPDATE Contact_PublicGroup
SET Sort= CGU.Sort,ModUserNo= contacts_downpublicgroup.userno,ModDate=NOW()
FROM  GroupUpdate CGU WHERE  CGU.PublicGroupNo=Contact_PublicGroup.PublicGroupNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_downsharegroup
CREATE OR REPLACE FUNCTION public.contacts_downsharegroup(userno integer DEFAULT 70, groupno integer DEFAULT 643, parentno integer DEFAULT 641)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
WITH RECURSIVE GroupTmp AS (select CG.*
from Contact_ShareGroup CG
WHERE  CG.ParentNo=contacts_downsharegroup.parentno AND CG.IsDelete= FALSE AND CG.Sort >= (SELECT Sort FROM Contact_ShareGroup WHERE ShareGroupNo=contacts_downsharegroup.groupno)
ORDER BY Sort ASC)
,
GroupUpdate AS(SELECT T.ShareGroupNo,T1.Sort
FROM GroupTmp T
LEFT JOIN GroupTmp T1 ON T1.ShareGroupNo <> T.ShareGroupNo)
UPDATE Contact_ShareGroup
SET Sort= CGU.Sort,ModUserNo= contacts_downsharegroup.userno,ModDate=NOW()
FROM  GroupUpdate CGU WHERE  CGU.ShareGroupNo=Contact_ShareGroup.ShareGroupNo;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_finall
CREATE OR REPLACE FUNCTION public.contacts_finall(userno integer, serchtype integer, serchtext character varying, viewcount integer, currentpageindex integer, initial character varying, sortcolumn character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF SerchType = 8 THEN
		IF Initial = 'ETC' THEN
			RETURN QUERY
			SELECT * FROM (SELECT
			CONVERT(INT,COUNT(*) OVER()) AS TotalCnt
			,CONVERT(INT, ROW_NUMBER() OVER (
			ORDER BY
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
			)) AS RowNum
			,C.Company
			,C.Depart
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,U.Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			FROM (SELECT * FROM ContactsUser WHERE RegUserNo=contacts_finall.userno AND UseYn='Y') U
			LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
			LEFT JOIN (SELECT * FROM ContactsAddress WHERE RegUserNo=contacts_finall.userno) A ON A.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsCompany WHERE RegUserNo=contacts_finall.userno) C ON C.UserSeq=U.Seq
