			LEFT JOIN (SELECT * FROM ContactsNumber WHERE RegUserNo=contacts_finduser.userno) N ON N.UserSeq=U.Seq
			LEFT JOIN (SELECT * FROM ContactsSns WHERE RegUserNo=contacts_finduser.userno) S ON S.UserSeq=U.Seq
