-- OBJECT ROUTINE public/dbo.contacts_getcontactgroup
CREATE OR REPLACE FUNCTION public.contacts_getcontactgroup(userno integer DEFAULT 70, langcode character varying DEFAULT 'KO'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH RECURSIVE ContactsGroups AS (
		   SELECT CGP.GroupNo,CGP.GroupNo AS RootGroupNo, CGP.GroupName, CGP.RegUserNo, CGP.RegDate, CGP.Memo, CGP.ParentGNo, CGP.Sort, CGP.IsDefault,CGP.UseYn
		  FROM ContactsGroup CGP
		  WHERE CGP.UseYn='Y' AND CGP.ParentGNo=0 AND  CGP.RegUserNo=contacts_getcontactgroup.userno
		  UNION ALL
		  SELECT CGC.GroupNo,C.RootGroupNo, CGC.GroupName, CGC.RegUserNo, CGC.RegDate, CGC.Memo, CGC.ParentGNo, CGC.Sort, CGC.IsDefault,CGC.UseYn
		  FROM ContactsGroup CGC
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo AND CGC.UseYn='Y' AND   CGC.RegUserNo=contacts_getcontactgroup.userno
	)
	SELECT CG.GroupNo AS Id,CG.GroupName AS JsonName,CG.ParentGNo AS ParentNo  ,
	(
		SELECT COUNT(*)
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq
		WHERE U.UseYn='Y' AND C.GroupNo =CG.GroupNo
	) AS ShareNumber,
	CASE WHEN STRPOS(CG.GroupName, '{')>0 THEN (SELECT StringValue FROM ParseJson( CG.GroupName)  WHERE NAME=contacts_getcontactgroup.langcode) ELSE CG.GroupName END AS Name
	FROM ContactsGroups  CG
	WHERE CG.RegUserNo=contacts_getcontactgroup.userno AND CG.UseYn='Y' ORDER BY CG.Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactscount
CREATE OR REPLACE FUNCTION public.contacts_getcontactscount(reguserno integer, ts character varying, te character varying, search character varying, searchmode character varying, groupno integer, mode character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    pagingqry character varying;
    countqry character varying;
    param character varying;
    searchtxt character varying;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN





	PagingQry := 'SELECT count(*) cnt FROM;
				(SELECT ROW_NUMBER() OVER(ORDER BY RegDate DESC) ROWNUM, Seq,Name,Memo FROM ContactsUser';

	CountQry := 'SELECT COUNT(*) CNT FROM ContactsUser';
	PARAM := 'P_RegUserNo INT,;
	P_TS NVARCHAR(5),
	P_TE NVARCHAR(5),
	P_GroupNo INT';

	IF GroupNo > 0 THEN
		pagingqry := COALESCE(pagingqry, '') || COALESCE((' CU INNER JOIN ContactsGroupUser CG
ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq '), '');

		countqry := COALESCE(countqry, '') || COALESCE((' CU INNER JOIN ContactsGroupUser CG
ON CU.RegUserNo = CG.RegUserNo AND CU.Seq=CG.UserSeq '), '');

		IF TS = '' AND TE = '' THEN
			IF Mode = '0' THEN
				pagingqry := COALESCE(pagingqry, '') || COALESCE(('WHERE CU.RegUserNo=P_RegUserNo AND GroupNo=P_GroupNo) PagingTable'), '');
			ELSE
				countqry := COALESCE(countqry, '') || COALESCE(('WHERE CU.RegUserNo=P_RegUserNo AND GroupNo=P_GroupNo'), '');
			END IF;
		ELSE
			IF Mode = '0' THEN
				pagingqry := COALESCE(pagingqry, '') || COALESCE(('WHERE CU.RegUserNo=P_RegUserNo AND GroupNo=P_GroupNo AND
Name BETWEEN P_TS AND P_TE) PagingTable'), '');
			ELSE
				countqry := COALESCE(countqry, '') || COALESCE(('WHERE CU.RegUserNo=P_RegUserNo AND GroupNo=P_GroupNo AND Name BETWEEN P_TS AND P_TE'), '');
			END IF;
		END IF;
	ELSE

		pagingqry := COALESCE(pagingqry, '') || COALESCE((' '), '');
		countqry := COALESCE(countqry, '') || COALESCE((' '), '');

		IF Search = '' THEN
			SearchTxt := '';
		ELSE
			IF SearchMode = '0' THEN
				SearchTxt := ' AND Name ILIKE ''%' || Search || '%''';
			ELSIF SearchMode = '1' THEN
				SearchTxt := '';
			ELSIF SearchMode = '2' THEN
				SearchTxt := '';
			ELSE
				SearchTxt := ' AND Memo ILIKE ''%' || Search || '%''';
			END IF;
		END IF;

		IF TS = '' AND TE = '' THEN
			IF Mode = '0' THEN
				pagingqry := COALESCE(pagingqry, '') || COALESCE(('WHERE RegUserNo=P_RegUserNo' || SearchTxt || ') PagingTable'), '');
			ELSE
				countqry := COALESCE(countqry, '') || COALESCE(('WHERE RegUserNo=P_RegUserNo' || SearchTxt), '');
			END IF;
		ELSE
			IF Mode = '0' THEN
				pagingqry := COALESCE(pagingqry, '') || COALESCE(('WHERE RegUserNo=P_RegUserNo AND Name BETWEEN P_TS AND P_TE' || SearchTxt || ') PagingTable'), '');
			ELSE
				countqry := COALESCE(countqry, '') || COALESCE(('WHERE RegUserNo=P_RegUserNo AND Name BETWEEN P_TS AND P_TE' || SearchTxt), '');
			END IF;
		END IF;
	END IF;

	IF Mode = '0' THEN
		EXECUTE PagingQry; -- TODO: rewrite named sp_executesql bindings as PostgreSQL USING parameters;
	ELSE
		EXECUTE CountQry; -- TODO: rewrite named sp_executesql bindings as PostgreSQL USING parameters;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactsforoutlook
CREATE OR REPLACE FUNCTION public.contacts_getcontactsforoutlook(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT
		COALESCE(CUO.OutlookEntryID,'') AS OutlookEntryID,
		COALESCE(CGO.OutlookFolderEntryID,'') AS FolderEntryID,
		COALESCE(CG.GroupNo,0) AS GroupNo,
		COALESCE(CG.GroupName,'') AS FolderName,
		CU.Seq,
		CU.FirstName,
		CU.LastName,
		CU.RegUserNo,
		COALESCE((SELECT Company FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq),'') As Company,
		COALESCE((SELECT Depart FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq),'') As Department,
		COALESCE((SELECT Position FROM ContactsCompany CC WHERE CC.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq),'') As Position,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq ORDER BY IsDefault DESC, seq),'') AS Email_01,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq AND CE.Seq NOT IN(SELECT Seq FROM ContactsEmail CE2 WHERE CE.UserSeq = CE2.UserSeq ORDER BY IsDefault DESC,Seq) ORDER BY IsDefault DESC,Seq),'') AS Email_02,
		COALESCE((SELECT Value FROM ContactsEmail CE WHERE CE.UserSeq = CU.Seq AND CE.Seq NOT IN(SELECT Seq FROM ContactsEmail CE2 WHERE CE.UserSeq = CE2.UserSeq ORDER BY IsDefault DESC,Seq) ORDER BY IsDefault DESC,Seq),'') AS Email_03,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '0' ORDER BY IsDefault DESC,Seq),'') AS MobileNumber,
		COALESCE((SELECT Value FROM ContactsHomepage CH WHERE CH.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq),'') AS HomePage,
		COALESCE((SELECT Value FROM ContactsSns CS WHERE CS.UserSeq = CU.Seq ORDER BY IsDefault DESC, Seq),'') AS Messenger,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '1' ORDER BY IsDefault DESC,Seq),'') AS HomeTelNumber,
		COALESCE((SELECT ZipCode1 || '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '1' ORDER BY IsDefault DESC, Seq),'') AS HomeZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '1' ORDER BY IsDefault DESC, Seq),'') AS HomeAddr,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '3' ORDER BY IsDefault DESC,Seq),'') AS HomeFaxNumber,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '2' ORDER BY IsDefault DESC,Seq),'') AS CompanyTelNumber,
		COALESCE((SELECT ZipCode1 || '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '0' ORDER BY IsDefault DESC, Seq),'') AS CompanyZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '0' ORDER BY IsDefault DESC, Seq),'') AS CompanyAddr,
		COALESCE((SELECT Value FROM ContactsNumber CN WHERE CN.UserSeq = CU.Seq AND CN.Type = '8' ORDER BY IsDefault DESC,Seq),'') AS OtherTelNumber,
		COALESCE((SELECT ZipCode1 || '-' || ZipCode2 FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '8' ORDER BY IsDefault DESC, Seq),'') AS OtherZipCode,
		COALESCE((SELECT Address FROM ContactsAddress CA WHERE CA.UserSeq = CU.Seq AND CA.Type = '8' ORDER BY IsDefault DESC, Seq),'') AS OtherAddr,
		CU.Memo
	FROM ContactsUser CU
	LEFT JOIN ContactsUserOutlook CUO ON CU.Seq = CUO.Seq
	INNER JOIN ContactsGroupUser CGU ON CU.Seq = CGU.UserSeq
	LEFT JOIN ContactsGroup CG ON CG.GroupNo = CGU.GroupNo
	LEFT JOIN ContactsGroupOutlook CGO ON CG.GroupNo = CGO.GroupNo
	WHERE CU.UseYn = 'Y'
	AND CU.RegUserNo = contacts_getcontactsforoutlook.userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getcontactsgroup
CREATE OR REPLACE FUNCTION public.contacts_getcontactsgroup(reguserno integer, pgroupno integer)
 RETURNS SETOF record
