-- OBJECT ROUTINE public/dbo.contacts_getcountchilduser
CREATE OR REPLACE FUNCTION public.contacts_getcountchilduser(seq integer, reguserno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
select COUNT(*) count FROM ContactsUser WHERE UseYn = 'Y'  AND Seq IN
 (SELECT UserSeq from ContactsGroupUser WHERE RegUserNo = contacts_getcountchilduser.reguserno
AND GroupNo IN (SELECT TreeID FROM public."GetChildGroup"(RegUserNo, Seq)));
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getdefaultboxcount
CREATE OR REPLACE FUNCTION public.contacts_getdefaultboxcount(reguserno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
select count(T.seq) from (
	SELECT distinct u.* FROM ContactsGroupUser G
	INNER JOIN ContactsUser U ON U.Seq = G.UserSeq AND U.UseYn='Y'
	inner join ContactsGroup cg on cg.groupno=g.groupno
	WHERE
	--U.RegUserNo=RegUserNo and
	(U.RegUserNo=contacts_getdefaultboxcount.reguserno Or U.Share='300' OR (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN public."Organization_GetDepartmentsByUser"(RegUserNo) DP ON DP.DepartNo = C.DepartNo))))
	--and cg.isdefault='0' and
	--cg.UseYn='Y' AND
	--G.GroupNo=0
	) as T;
END;
$function$


