-- OBJECT ROUTINE public/dbo.contacts_getdepartallowaccess
CREATE OR REPLACE FUNCTION public.contacts_getdepartallowaccess(itemnos character varying DEFAULT '16'::character varying, langcode character varying DEFAULT 'VN'::character varying)
 RETURNS SETOF record
