BEGIN


	RETURN QUERY
	SELECT A.AllowAccessNo,A.DepartNo,A.AllowValue,A.ItemNo,
	CASE WHEN LangCode='KO' THEN D.Name ELSE COALESCE(D.Name_EN,D.Name) END AS DepartName,
		CASE WHEN A.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS IsAdmin ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue =2 OR A.AllowValue =6 THEN TRUE ELSE FALSE END AS IsRead ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue =4 OR A.AllowValue =6 THEN TRUE ELSE FALSE END AS IsWrite ,
		FALSE  AS DisableAdmin ,
		CASE WHEN A.AllowValue%2<>0 THEN TRUE ELSE FALSE END AS DisableWrite ,
		CASE WHEN A.AllowValue%2<>0 OR A.AllowValue=4 OR A.AllowValue=6 THEN TRUE ELSE FALSE END AS DisableRead
	FROM Contact_DepartAllowAccess A
	INNER JOIN Organization_Departments D ON D.DepartNo=A.DepartNo
	WHERE A.ItemNo IN  (SELECT * FROM Contacts_StringToListInt(ItemNos));
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getdepartmentboxcount
CREATE OR REPLACE FUNCTION public.contacts_getdepartmentboxcount(reguserno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
select count(T.seq) from (
	SELECT distinct u.* FROM ContactsGroupUser G
	INNER JOIN ContactsUser U ON U.Seq = G.UserSeq AND U.UseYn='Y'
	inner join ContactsGroup cg on cg.groupno=g.groupno
	WHERE (U.RegUserNo=contacts_getdepartmentboxcount.reguserno and SUBSTRING(U.Share,1,3)='200') or (SUBSTRING(U.Share,1,3)='200' and (U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN public."Organization_GetDepartmentsByUser"(RegUserNo) DP ON DP.DepartNo = C.DepartNo)))
	) as T;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getdupelist
CREATE OR REPLACE FUNCTION public.contacts_getdupelist(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT U.Seq, FirstName, LastName, E.Seq AS E_Seq, E.Value AS EMail, N.Seq AS N_Seq, N.Value AS Number,
		RANK() OVER(ORDER BY E.Value) AS Group1,
		RANK() OVER(ORDER BY N.Value) AS Group2
	FROM ContactsUser U
	LEFT JOIN ContactsEmail E ON U.Seq = E.UserSeq
	LEFT JOIN ContactsNumber N ON U.Seq = N.UserSeq
	WHERE U.RegUserNo = contacts_getdupelist.userno
	AND UseYn = 'Y'
	AND (
		 E.Value IN (
			SELECT
				Value
			FROM ContactsEmail
			WHERE RegUserNo = contacts_getdupelist.userno
			AND Value <> ''
			GROUP BY Value
			HAVING COUNT(VALUE) > 1
		 ) OR
		 N.Value IN (
			SELECT
				Value
			FROM ContactsNumber
			WHERE RegUserNo = contacts_getdupelist.userno
			AND Value <> ''
			GROUP BY Value
			HAVING COUNT(VALUE) > 1
		 )
	);
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getgroupbyseq
CREATE OR REPLACE FUNCTION public.contacts_getgroupbyseq(userseq integer DEFAULT 0, langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	WITH RECURSIVE SHAREGROUP AS (
		SELECT S.GroupNo,
		CASE WHEN STRPOS(G.GroupName, '{')>0 THEN (SELECT StringValue FROM ParseJson(G.GroupName)  WHERE NAME=contacts_getgroupbyseq.langcode) ELSE G.GroupName END AS Name
		FROM ContactsGroupUser S
		INNER JOIN ContactsGroup G ON G.GroupNo=S.GroupNo AND  G.UseYn='Y'
		Where S.UserSeq=contacts_getgroupbyseq.userseq
		--
		UNION ALL
		SELECT S.ShareGroupNo AS GroupNo,
			CASE WHEN STRPOS(G.ShareGroupName, '{')>0 THEN (SELECT StringValue FROM ParseJson(G.ShareGroupName)  WHERE NAME=contacts_getgroupbyseq.langcode) ELSE G.ShareGroupName END AS Name
		FROM Contact_ShareGroupUser S
		INNER JOIN Contact_ShareGroup G ON G.ShareGroupNo=S.ShareGroupNo AND   G.IsDelete= FALSE
		Where S.UserSeq=contacts_getgroupbyseq.userseq
		--
		 UNION ALL
		SELECT S.PublicGroupNo AS GroupNo,
		CASE WHEN STRPOS(G.PublicGroupName, '{')>0 THEN (SELECT StringValue FROM ParseJson(G.PublicGroupName)  WHERE NAME=contacts_getgroupbyseq.langcode) ELSE G.PublicGroupName END AS Name
		FROM Contact_PublicGroupUser S
		INNER JOIN Contact_PublicGroup G ON G.PublicGroupNo=S.PublicGroupNo AND  G.IsDelete= FALSE
		Where S.UserSeq=contacts_getgroupbyseq.userseq
		--ORDER BY S.UserSeq DESC LIMIT 1
	)
	SELECT T.GroupNo,T.Name FROM SHAREGROUP T ORDER BY T.GroupNo DESC;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getgroupbyuser
CREATE OR REPLACE FUNCTION public.contacts_getgroupbyuser(reguserno integer DEFAULT NULL::integer, userseq integer DEFAULT 0)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


 IF (SELECT COUNT(*) FROM ContactsGroup  WHERE RegUserNo=contacts_getgroupbyuser.reguserno AND UseYn='Y')<=0 THEN
	PERFORM contacts_insertgroup(RegUserNo,'임시 그룹',0);
 END IF;


	RETURN QUERY
	SELECT distinct c.GroupNo, c.GroupName, c.RegUserNo, c.RegDate, c.Memo, c.ParentGNo, c.Sort, c.IsDefault,
	(
		SELECT COUNT(*)
		FROM ContactsGroupUser Cc
		INNER JOIN ContactsUser U ON U.Seq = Cc.UserSeq AND U.UseYn='Y'
		WHERE Cc.GroupNo = c.GroupNo
	) AS UserCount,
	UseYn
	FROM ContactsGroup c
	left join ContactsGroupUser g on c.groupno=g.groupno
	WHERE c.RegUserNo=contacts_getgroupbyuser.reguserno AND c.UseYn='Y' --and --g.userseq=UserSeq
	 ORDER BY c.Sort;
END;
$function$


