-- OBJECT ROUTINE public/dbo.contacts_gethistorylist
CREATE OR REPLACE FUNCTION public.contacts_gethistorylist(userno integer, currpage integer, pagesize integer, searchtype integer, searchday integer DEFAULT 0, searchdate1 date DEFAULT ('now'::text)::date, searchdate2 date DEFAULT ('now'::text)::date)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF SearchType = 1 THEN
		RETURN QUERY
		SELECT
			RowNum,
			HistoryNo,
			Seq,
			FirstName,
			LastName,
			Memo,
			ModDate
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY U.ModDate DESC) AS RowNum,
				U.HistoryNo,
				U.Seq,
				U.FirstName,
				U.LastName,
				U.Memo,
				U.ModDate
			  FROM ContactsUserHistory U
			WHERE U.RegUserNo = contacts_gethistorylist.userno
			AND U.ModDate >= DATEADD(dd, SearchDay, NOW())
		) A
		WHERE RowNum BETWEEN ((CurrPage-1) * PageSize + 1) AND (CurrPage * PageSize);
	ELSE
		RETURN QUERY
		SELECT
			RowNum,
			HistoryNo,
			Seq,
			FirstName,
			LastName,
			Memo,
			ModDate
		FROM
		(
			SELECT
				ROW_NUMBER() OVER(ORDER BY U.ModDate DESC) AS RowNum,
				U.HistoryNo,
				U.Seq,
				U.FirstName,
				U.LastName,
				U.Memo,
				U.ModDate
			  FROM ContactsUserHistory U
			WHERE U.RegUserNo = contacts_gethistorylist.userno
			AND U.ModDate BETWEEN SearchDate1 and SearchDate2
		) A
		WHERE RowNum BETWEEN ((CurrPage-1) * PageSize + 1) AND (CurrPage * PageSize);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_gethistorylistcount
CREATE OR REPLACE FUNCTION public.contacts_gethistorylistcount(userno integer, searchtype integer, searchday integer DEFAULT 0, searchdate1 date DEFAULT ('now'::text)::date, searchdate2 date DEFAULT ('now'::text)::date)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	IF SearchType = 1 THEN
		RETURN QUERY
		SELECT
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = contacts_gethistorylistcount.userno
		AND U.ModDate >= DATEADD(dd, SearchDay, NOW());
	ELSE
		RETURN QUERY
		SELECT
			COUNT(*) AS CNT
		  FROM ContactsUserHistory U
		WHERE U.RegUserNo = contacts_gethistorylistcount.userno
		AND U.ModDate BETWEEN SearchDate1 AND SearchDate2;
	END IF;
END;
$function$


