 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT CA.UserSeq,CA.Longitude,CA.Latitude,CU.FirstName,CU.LastName,CA.Address
	FROM ContactsAddress CA
