				GroupNo
			);

			GroupList := SUBSTRING(GroupList,STRPOS(GroupList, ',')+1,LEN(GroupList));
		END LOOP;
IF IsAdmin = TRUE THEN
		RETURN QUERY
		SELECT distinct
			Seq,
