-- OBJECT ROUTINE public/dbo.contacts_getprivateboxcount
CREATE OR REPLACE FUNCTION public.contacts_getprivateboxcount(reguserno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
select count(T.seq) from (
	SELECT distinct u.* FROM ContactsGroupUser G
	INNER JOIN ContactsUser U ON U.Seq = G.UserSeq AND U.UseYn='Y'
	inner join ContactsGroup cg on cg.groupno=g.groupno
	WHERE
	--U.RegUserNo=RegUserNo and
	(U.RegUserNo=contacts_getprivateboxcount.reguserno) AND SUBSTRING(U.Share,1,3)='100'
	) as T;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getpublicboxcount
CREATE OR REPLACE FUNCTION public.contacts_getpublicboxcount(reguserno integer DEFAULT 70)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
WITH 	GroupUsers AS(SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM ContactsGroupUser GU)
SELECT COUNT(T.seq) from (
	SELECT DISTINCT U.*
	FROM  ContactsUser U
	LEFT JOIN  GroupUsers G ON U.Seq = G.UserSeq AND U.UseYn='Y'  AND G.Nm=1
	LEFT JOIN ContactsGroup cg on cg.groupno=g.groupno AND CG.UseYn='Y'
	WHERE SUBSTRING(U.Share,1,3)='300' AND U.UseYn = 'Y') as T;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getpublicgroup
CREATE OR REPLACE FUNCTION public.contacts_getpublicgroup(langcode character varying DEFAULT 'KO'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT PG.PublicGroupNo AS Id,PG.PublicGroupName AS JsonName,COALESCE(CASE WHEN STRPOS(PG.PublicGroupName, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(PG.PublicGroupName)  WHERE NAME=contacts_getpublicgroup.langcode),(SELECT StringValue FROM ParseJson(PG.PublicGroupName)  WHERE NAME='KO')) ELSE PG.PublicGroupName END,'') AS Name , PG.ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM  Contact_PublicGroup PG
	LEFT JOIN  ( SELECT P.PublicGroupNo, Count(P.PublicGroupNo) AS ShareNumber
				FROM Contact_PublicGroupUser  P
				INNER JOIN ContactsUser U ON U.Seq = P.UserSeq AND U.UseYn='Y'
				WHERE P.IsDelete= FALSE
				GROUP BY P.PublicGroupNo) SU ON SU.PublicGroupNo = PG.PublicGroupNo
	WHERE PG.IsDelete= FALSE
	ORDER BY  PG.ParentNo, PG.Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getranklist
CREATE OR REPLACE FUNCTION public.contacts_getranklist(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT RowNum,
		Seq,
		FirstName,
		LastName,
		Memo,
		ViewCount
	FROM
	(
		SELECT
			ROW_NUMBER() OVER(ORDER BY ViewCount DESC) AS RowNum,
			U.Seq,
			U.FirstName,
			U.LastName,
			U.Memo,
			U.ViewCount
		  FROM ContactsUser U
		  JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
		WHERE U.RegUserNo = contacts_getranklist.userno
		AND UseYn = 'Y'
	) A;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getranklistcount
CREATE OR REPLACE FUNCTION public.contacts_getranklistcount(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	SELECT
		COUNT(*) AS CNT
	  FROM ContactsUser U
		JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
	WHERE U.RegUserNo = contacts_getranklistcount.userno
	AND UseYn = 'Y';
END;
$function$


