-- OBJECT ROUTINE public/dbo.contacts_getsharedepartmentdefault
CREATE OR REPLACE FUNCTION public.contacts_getsharedepartmentdefault(userno integer DEFAULT 222, langcode character varying DEFAULT 'KO'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

 RETURN QUERY
 SELECT OD.DepartNo,CASE LangCode WHEN 'EN' THEN  COALESCE(OD.Name_EN,OD.Name) WHEN 'VN' THEN  COALESCE(OD.Name_VN,OD.Name) WHEN 'CH' THEN COALESCE(OD.Name_CH,OD.Name)  WHEN 'JP' THEN COALESCE(OD.Name_JP,OD.Name) ELSE OD.Name END AS Name
 FROM Contact_DepartAllowAccess DA
 INNER JOIN Organization_BelongToDepartment  OB ON OB.DepartNo=DA.DepartNo
 INNER JOIN Organization_Departments OD ON OD.DepartNo=OB.DepartNo

 WHERE OB.UserNo=contacts_getsharedepartmentdefault.userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroup
CREATE OR REPLACE FUNCTION public.contacts_getsharegroup(userno integer DEFAULT 222, isadmin boolean DEFAULT false, langcode character varying DEFAULT 'KO'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

IF IsAdmin = TRUE THEN
	RETURN QUERY
	SELECT * FROM (
	SELECT SG.ShareGroupNo AS Id,
	ShareGroupName AS JsonName,
	COALESCE(CASE WHEN STRPOS(SG.ShareGroupName, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME=contacts_getsharegroup.langcode),(SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME='KO')) ELSE SG.ShareGroupName END,'') AS Name ,
	ParentNo ,
	COALESCE(SU.ShareNumber,0) AS ShareNumber,
	SG.Sort
	FROM  Contact_ShareGroup SG
	LEFT JOIN  ( SELECT ShareGroupNo, Count(ShareGroupNo) AS ShareNumber
				FROM Contact_ShareGroupUser S
				INNER JOIN ContactsUser U ON U.Seq=S.UserSeq AND U.UseYn='Y'
				WHERE S.IsDelete= FALSE
				GROUP BY S.ShareGroupNo) SU ON SU.ShareGroupNo = SG.ShareGroupNo
	WHERE SG.IsDelete= FALSE
	UNION ALL
	SELECT 0 AS Id,'' as JsonName,'' AS Name,-1 AS ParentNo,(SELECT Count(*)
				FROM ContactsUser U
				LEFT OUTER JOIN  Contact_ShareGroupUser S   ON U.Seq=S.UserSeq AND S.IsDelete= FALSE
				WHERE  U.UseYn='Y'  AND SUBSTRING(U.Share,1,3)='200') AS ShareNumber,
				0 AS Sort

	) T
	ORDER BY  T.ParentNo, T.Sort;
ELSE
	RETURN QUERY
	WITH RECURSIVE DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo
		FROM Contact_DepartAllowAccess BD
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE  OB.UserNo=contacts_getsharegroup.userno AND OB.IsDefault= TRUE
	),SHARE AS (
		SELECT S.Seq FROM ContactsSharers S
		INNER JOIN Organization_BelongToDepartment D ON D.DepartNo=S.DepartNo
		WHERE  D.UserNo=contacts_getsharegroup.userno
	)
	SELECT COALESCE(SG.ShareGroupNo,0) AS Id,
	COALESCE(ShareGroupName,'') AS JsonName,
	COALESCE(CASE WHEN STRPOS(SG.ShareGroupName, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME=contacts_getsharegroup.langcode),(SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME='KO')) ELSE SG.ShareGroupName END,'') AS Name ,
	COALESCE(ParentNo,-1) AS ParentNo,
	COALESCE(SU.ShareNumber,0) AS ShareNumber
	FROM DEPARTPERMISSION D
	LEFT JOIN Contact_ShareGroup SG   ON D.ItemNo=SG.ShareGroupNo AND SG.IsDelete= FALSE
	LEFT JOIN  ( SELECT ShareGroupNo, Count(ShareGroupNo) AS ShareNumber
				FROM Contact_ShareGroupUser SG
				INNER JOIN ContactsUser U ON U.Seq=SG.UserSeq AND U.UseYn='Y'
				INNER JOIN SHARE CS ON CS.Seq=U.Seq
				WHERE SG.IsDelete= FALSE
				GROUP BY SG.ShareGroupNo
				--UNION
				--SELECT 0 AS ShareGroupNo,
				--(SELECT COUNT (*)FROM ContactsUser U
				--LEFT OUTER JOIN Contact_ShareGroupUser S  ON U.Seq=S.UserSeq AND  S.IsDelete= FALSE
				--INNER JOIN SHARE CS ON CS.Seq=U.Seq
				--WHERE SUBSTRING(U.Share,1,3)='200'  AND U.UseYn='Y') AS ShareNumber
				) SU ON SU.ShareGroupNo =D.ItemNo
	WHERE   D.AllowValue>0
	ORDER BY  SG.ParentNo, SG.Sort;
END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getsharegroupbyuser
CREATE OR REPLACE FUNCTION public.contacts_getsharegroupbyuser(userno integer DEFAULT 70, isadmin boolean DEFAULT true, langcode character varying DEFAULT 'KO'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

IF IsAdmin = TRUE THEN
	RETURN QUERY
	SELECT * FROM (SELECT SG.ShareGroupNo AS Id,
	ShareGroupName AS JsonName,
	COALESCE(CASE WHEN STRPOS(SG.ShareGroupName, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME=contacts_getsharegroupbyuser.langcode),(SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME='KO')) ELSE SG.ShareGroupName END,'') AS Name ,
	ParentNo ,Sort
	FROM  Contact_ShareGroup SG
	WHERE SG.IsDelete= FALSE
	UNION ALL
	SELECT 0 AS Id,'' as JsonName,'' AS Name,-1 AS ParentNo,0 AS Sort) T
	ORDER BY  T.ParentNo, T.Sort;
ELSE
	RETURN QUERY
	WITH RECURSIVE DEPARTPERMISSION AS (
		Select ItemNo ,AllowValue,AllowAccessNo
		FROM Contact_DepartAllowAccess BD
		INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
		WHERE  OB.UserNo=contacts_getsharegroupbyuser.userno AND OB.IsDefault= TRUE
	)
	SELECT SG.ShareGroupNo AS Id,
	COALESCE(ShareGroupName,'') AS JsonName,
	COALESCE(CASE WHEN STRPOS(SG.ShareGroupName, '{')>0 THEN COALESCE((SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME=contacts_getsharegroupbyuser.langcode),(SELECT StringValue FROM ParseJson(SG.ShareGroupName)  WHERE NAME='KO')) ELSE SG.ShareGroupName END,'') AS Name ,
	COALESCE(ParentNo,-1) AS ParentNo
	FROM DEPARTPERMISSION D
	LEFT JOIN Contact_ShareGroup SG   ON D.ItemNo=SG.ShareGroupNo AND SG.IsDelete= FALSE
	--FROM  Contact_ShareGroup SG
	--INNER JOIN DEPARTPERMISSION D ON D.ItemNo=SG.ShareGroupNo AND SG.IsDelete= FALSE
	 WHERE   D.AllowValue>4
	ORDER BY  SG.ParentNo, SG.Sort;
END IF;
END;
$function$


