$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserbypublicgroup
CREATE OR REPLACE FUNCTION public.contacts_getuserbypublicgroup(userno integer DEFAULT 70, groupno integer DEFAULT 8, viewcount integer DEFAULT 10, currentpageindex integer DEFAULT 1, initial character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT 'DESC_RegDate'::character varying, serchtype integer DEFAULT 0, serchtext character varying DEFAULT ''::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

			RETURN QUERY
			WITH PhoneNumbers AS (SELECT CT.UserSeq,CT.Value ,CT.Type  ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm FROM ContactsNumber CT ),
			--GroupUsers AS(SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.GroupNo ORDER BY GU.RegDate) AS Nm FROM Contact_PublicGroup GU),
			ContactsEmails AS(SELECT     CE.UserSeq,CE.Value,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE),
			ContactsCompanys AS(SELECT      C.UserSeq, C.Company, C.Depart, C.Position,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C)
			SELECT * FROM (SELECT
			CAST(COUNT(*) OVER() AS INT) AS TotalCount
			,CAST( ROW_NUMBER() OVER (
			ORDER BY
				CASE WHEN SortColumn='' THEN U.LastName + U.FirstName END ASC,
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName + U.FirstName END ASC,
				CASE WHEN SortColumn='ASC_NAME' THEN U.LastName + U.FirstName END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName + U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_IMPORTANT' THEN U.Important END ASC,
				CASE WHEN SortColumn='DESC_IMPORTANT' THEN U.Important END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
			) AS INT) RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,U.LastName || ' ' || U.FirstName AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U
			LEFT JOIN Contact_PublicGroupUser SG ON SG.UserSeq=U.Seq AND SG.IsDelete= FALSE
			LEFT JOIN Contact_PublicGroup G ON G.PublicGroupNo= SG.PublicGroupNo AND G.IsDelete= FALSE
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND  C.Nm=1
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq AND E.Nm=1
			--LEFT JOIN GroupUsers GU ON GU.UserSeq = U.Seq AND GU.Nm=1
			--LEFT JOIN ContactsGroup G ON G.GroupNo= GU.GroupNo AND G.UseYn='Y'
			LEFT JOIN Organization_users OU ON OU.Enabled = TRUE AND  OU.UserNo=U.RegUserNo
			WHERE (SUBSTRING(U.Share,1,3)='300')
			AND COALESCE(SG.PublicGroupNo,0)=contacts_getuserbypublicgroup.groupno
			AND U.UseYn = 'Y'
			AND (serchtext=''
					OR (serchtext !='' AND (
						U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'
						OR N0.Value ILIKE '%' || SerchText || '%'
						OR N2.Value ILIKE '%' || SerchText || '%'
						OR C.Company ILIKE '%' || SerchText || '%'
						OR C.Depart ILIKE '%' || SerchText || '%'
						OR C.Position ILIKE '%' || SerchText || '%'
						OR E.Value ILIKE '%' || SerchText || '%'
						OR G.PublicGroupName ILIKE '%' || SerchText || '%'
						OR U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'))
					OR (SerchType = 1 AND N0.Value ILIKE '%' || SerchText || '%' OR N2.Value ILIKE '%' || SerchText || '%')
					OR (SerchType = 2 AND C.Company ILIKE '%' || SerchText || '%')
					OR (SerchType = 3 AND C.Depart ILIKE '%' || SerchText || '%')
					OR (SerchType = 4 AND C.Position ILIKE '%' || SerchText || '%')
					OR (SerchType = 5 AND E.Value ILIKE '%' || SerchText || '%')
					OR (SerchType = 6 AND G.PublicGroupName ILIKE '%' || SerchText || '%')
					OR (SerchType = 8 AND U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%')
			)
			AND (Initial=''
				OR REPLACE(U.LastName || ' ' || U.FirstName,' ' ,'') ILIKE Initial || '%'
				OR Initial='other' AND  (U.LastName || ' ' || U.FirstName NOT ILIKE '%[0-9]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[A-Z]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[ㄱ-ㅎ]%')
				)
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserbysharegroup
CREATE OR REPLACE FUNCTION public.contacts_getuserbysharegroup(userno integer DEFAULT 70, groupno integer DEFAULT 0, viewcount integer DEFAULT 10, currentpageindex integer DEFAULT 1, initial character varying DEFAULT ''::character varying, sortcolumn character varying DEFAULT ''::character varying, serchtype integer DEFAULT 0, serchtext character varying DEFAULT ''::character varying, isadmin boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

IF IsAdmin = TRUE THEN
	RETURN QUERY
	WITH PhoneNumbers AS (
			SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT
		),GroupUsers AS(
			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm FROM Contact_ShareGroupUser GU WHERE IsDelete= FALSE
		),
		ContactsEmails AS(
			SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
		),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		)
		SELECT * FROM (SELECT
		CAST(COUNT(*) OVER() AS INT) AS TotalCount
		,CAST( ROW_NUMBER() OVER (
		ORDER BY
		CASE WHEN SortColumn='' THEN U.Important END DESC,
			CASE WHEN SortColumn='' THEN U.LastName + U.FirstName  END ASC,
			CASE WHEN SortColumn='ASC_NAME' THEN U.LastName + U.FirstName  END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName + U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
		) AS INT) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,U.LastName || ' ' || U.FirstName AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U
			LEFT JOIN GroupUsers SG ON SG.UserSeq=U.Seq  AND SG.Nm=1
			LEFT JOIN Contact_ShareGroup G ON G.ShareGroupNo= SG.ShareGroupNo AND G.IsDelete= FALSE
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq  AND E.Nm=1

			LEFT JOIN Organization_users OU ON OU.Enabled = TRUE AND  OU.UserNo=U.RegUserNo
			WHERE
			--((U.RegUserNo=UserNo AND SUBSTRING(U.Share,1,3)='200' AND COALESCE(SG.ShareGroupNo,0)=GroupNo)

			((SUBSTRING(U.Share,1,3)='200' AND COALESCE(SG.ShareGroupNo,0)=contacts_getuserbysharegroup.groupno)
			/*OR (SUBSTRING(U.Share,1,3)='200' AND U.Seq IN (select C.Seq
														from ContactsSharers C
														INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo = C.DepartNo AND DP.UserNo=contacts_getuserbysharegroup.userno)
			)*/
			)
			AND U.UseYn = 'Y'
			AND (serchtext=''
				OR ( serchtext !='' AND
				  (	   (SerchType = 0 AND
						(U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'
						OR (N0.Value ILIKE '%' || SerchText || '%' OR N2.Value ILIKE '%' || SerchText || '%')
						OR C.Company ILIKE '%' || SerchText || '%'
						OR C.Depart ILIKE '%' || SerchText || '%'
						OR C.Position ILIKE '%' || SerchText || '%'
						OR E.Value ILIKE '%' || SerchText || '%'
						OR G.ShareGroupName ILIKE '%' || SerchText || '%'
						OR U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'))
					OR (SerchType = 1 AND (N0.Value ILIKE '%' || SerchText || '%' OR N2.Value ILIKE '%' || SerchText || '%'))
					OR (SerchType = 2 AND C.Company ILIKE '%' || SerchText || '%')
					OR (SerchType = 3 AND C.Depart ILIKE '%' || SerchText || '%')
					OR (SerchType = 4 AND C.Position ILIKE '%' || SerchText || '%')
					OR (SerchType = 5 AND E.Value ILIKE '%' || SerchText || '%')
					OR (SerchType = 6 AND G.ShareGroupName ILIKE '%' || SerchText || '%')
					OR (SerchType = 8 AND U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%')
				  )

				)

			    )
			AND (Initial=''
				OR REPLACE(U.LastName || ' ' || U.FirstName,' ' ,'') ILIKE Initial || '%'
				OR Initial='other' AND  (U.LastName || ' ' || U.FirstName NOT ILIKE '%[0-9]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[A-Z]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[ㄱ-ㅎ]%')
			)
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;

	ELSE

		RETURN QUERY
		WITH PhoneNumbers AS (
			SELECT CT.* ,ROW_NUMBER() OVER(PARTITION BY CT.Type, CT.UserSeq ORDER BY CT.RegDate) AS Nm
			FROM ContactsNumber CT
		),GroupUsers AS(
			SELECT GU.*,ROW_NUMBER() OVER(PARTITION BY GU.UserSeq, GU.ShareGroupNo ORDER BY GU.RegDate) AS Nm FROM Contact_ShareGroupUser GU WHERE IsDelete= FALSE
		),
		ContactsEmails AS(
			SELECT  CE.*,ROW_NUMBER() OVER(PARTITION BY CE.UserSeq ORDER BY CE.RegDate) AS Nm FROM ContactsEmail CE
		),
		ContactsCompanys AS(
			SELECT  C.*,ROW_NUMBER() OVER(PARTITION BY C.UserSeq ORDER BY C.RegDate) AS Nm FROM ContactsCompany C
		),
		DEPARTPERMISSION AS (
			Select ItemNo ,AllowValue,AllowAccessNo
			FROM Contact_DepartAllowAccess BD
			INNER JOIN Organization_BelongToDepartment OB ON OB.DepartNo=BD.DepartNo
			WHERE  OB.UserNo=contacts_getuserbysharegroup.userno AND OB.IsDefault= TRUE AND GroupNo=BD.ItemNo
		)
		SELECT * FROM (SELECT
		CAST(COUNT(*) OVER() AS INT) AS TotalCount
		,CAST( ROW_NUMBER() OVER (
		ORDER BY
		CASE WHEN SortColumn='' THEN U.Important END DESC,
			CASE WHEN SortColumn='' THEN U.LastName + U.FirstName  END ASC,
			CASE WHEN SortColumn='ASC_NAME' THEN U.LastName + U.FirstName  END ASC,
				CASE WHEN SortColumn='DESC_NAME' THEN U.LastName + U.FirstName END DESC,
				CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
				CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
				CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
				CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC,
				CASE WHEN SortColumn='DESC_RegDate' THEN U.RegDate END DESC
		) AS INT) AS RowNum
			,COALESCE(C.Company,'') as Company
			,COALESCE(C.Depart,'') as Depart
			,COALESCE(C.Position,'') as Position
			,U.Seq
			,U.FirstName
			,U.LastName
			,U.RegUserNo
			,U.Memo
			,U.RegDate
			,COALESCE(U.Photo,'') AS Photo
			,U.ModDate
			,U.CheckDate
			,U.Share
			,U.UseYn
			,U.DelDate
			,U.Important
			,U.CallName
			,0 as isdefault
			,U.LastName || ' ' || U.FirstName AS FullName
			,N0.Value AS CellPhone
			,N2.Value AS CompanyPhone
			,E.Value AS Email
			,OU.Name AS RegUserName
			FROM ContactsUser U
			LEFT JOIN GroupUsers SG ON SG.UserSeq=U.Seq
			LEFT JOIN DEPARTPERMISSION P ON P.ItemNo=SG.ShareGroupNo
			LEFT JOIN Contact_ShareGroup G ON G.ShareGroupNo= SG.ShareGroupNo AND G.IsDelete= FALSE
			LEFT JOIN ContactsCompanys C ON C.UserSeq = U.Seq AND C.Nm=1
			LEFT JOIN PhoneNumbers  N0 ON N0.Type=0 AND N0.UserSeq=U.Seq AND N0.Nm=1
			LEFT JOIN PhoneNumbers  N2 ON N2.Type=2 AND N2.UserSeq=U.Seq AND N2.Nm=1
			LEFT JOIN ContactsEmails  E ON E.UserSeq=U.Seq  AND E.Nm=1
			LEFT JOIN Organization_users OU ON OU.Enabled = TRUE AND  OU.UserNo=U.RegUserNo

			WHERE
			((U.RegUserNo=contacts_getuserbysharegroup.userno AND SUBSTRING(U.Share,1,3)='200' AND GroupNo=0)
			--OR (SUBSTRING(U.Share,1,3)='200' AND COALESCE(SG.ShareGroupNo,0)=GroupNo AND U.Seq IN (select C.Seq from ContactsSharers C INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo = C.DepartNo AND DP.UserNo=UserNo))
			/*OR (SUBSTRING(U.Share,1,3)='200' AND (U.RegUserNo IN (SELECT UserNo
															FROM Organization_BelongToDepartment
															WHERE DepartNo IN (SELECT DepartNo FROM Organization_BelongToDepartment WHERE UserNo = contacts_getuserbysharegroup.userno))))
				*/
			OR (SUBSTRING(U.Share,1,3) ='200' AND GroupNo=SG.ShareGroupNo AND (U.Seq IN (select C.Seq
												from ContactsSharers  C
												INNER JOIN Organization_BelongToDepartment DP ON DP.DepartNo = C.DepartNo AND DP.UserNo = contacts_getuserbysharegroup.userno)))

			)
			AND U.UseYn = 'Y'
			AND (serchtext=''
				OR ( serchtext !='' AND
				  (	   (SerchType = 0 AND
						(U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'
						OR (N0.Value ILIKE '%' || SerchText || '%' OR N2.Value ILIKE '%' || SerchText || '%')
						OR C.Company ILIKE '%' || SerchText || '%'
						OR C.Depart ILIKE '%' || SerchText || '%'
						OR C.Position ILIKE '%' || SerchText || '%'
						OR E.Value ILIKE '%' || SerchText || '%'
						OR G.ShareGroupName ILIKE '%' || SerchText || '%'
						OR U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%'))
					OR (SerchType = 1 AND (N0.Value ILIKE '%' || SerchText || '%' OR N2.Value ILIKE '%' || SerchText || '%'))
					OR (SerchType = 2 AND C.Company ILIKE '%' || SerchText || '%')
					OR (SerchType = 3 AND C.Depart ILIKE '%' || SerchText || '%')
					OR (SerchType = 4 AND C.Position ILIKE '%' || SerchText || '%')
					OR (SerchType = 5 AND E.Value ILIKE '%' || SerchText || '%')
					OR (SerchType = 6 AND G.ShareGroupName ILIKE '%' || SerchText || '%')
					OR (SerchType = 8 AND U.LastName || ' ' || U.FirstName ILIKE '%' || SerchText || '%')
				  )

				)

			    )
			AND (Initial=''
				OR REPLACE(U.LastName || ' ' || U.FirstName,' ' ,'') ILIKE Initial || '%'
				OR Initial='other' AND  (U.LastName || ' ' || U.FirstName NOT ILIKE '%[0-9]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[A-Z]%' OR U.LastName || ' ' || U.FirstName NOT ILIKE '%[ㄱ-ㅎ]%')
			)
			) T
			WHERE T.RowNum
			BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
			AND CurrentPageIndex * ViewCount;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserdata
CREATE OR REPLACE FUNCTION public.contacts_getuserdata(reguserno integer, userseq integer, key character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	IF Key = 'number' THEN
		RETURN QUERY
		SELECT Value, Type FROM ContactsNumber  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'email' THEN
		RETURN QUERY
		SELECT Value,0 AS Type FROM ContactsEmail  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'days' THEN
		RETURN QUERY
		SELECT Value,0 AS Type FROM ContactsDays  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'comp' THEN
		RETURN QUERY
		SELECT Company As Value ,0 AS Type FROM ContactsCompany  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'dept' THEN
		RETURN QUERY
		SELECT Depart As Value ,0 AS Type FROM ContactsCompany  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'position' THEN
		RETURN QUERY
		SELECT Position As Value ,0 AS Type FROM ContactsCompany  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'addr' THEN
		RETURN QUERY
		SELECT '(' || ZipCode1 || '-' || ZipCode2 || ')' || Address  As Value ,0 AS Type FROM ContactsAddress
        WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'sns' THEN
		RETURN QUERY
		SELECT Value ,0 AS Type FROM ContactsSns  WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND IsDefault='1';

	ELSIF Key = 'memo' THEN
		RETURN QUERY
		SELECT Memo  As Value ,0 AS Type FROM ContactsUser  WHERE RegUserNo=contacts_getuserdata.reguserno AND Seq=contacts_getuserdata.userseq;

	ELSIF Key = 'firstname' THEN
		RETURN QUERY
		SELECT FirstName As Value ,0 AS Type FROM ContactsUser  WHERE RegUserNo=contacts_getuserdata.reguserno AND Seq=contacts_getuserdata.userseq;

	ELSIF Key = 'lastname' THEN
		RETURN QUERY
		SELECT LastName As Value ,0 AS Type FROM ContactsUser  WHERE RegUserNo=contacts_getuserdata.reguserno AND Seq=contacts_getuserdata.userseq;

	ELSIF Key = 'callname' THEN
		RETURN QUERY
		SELECT CallName As Value ,0 AS Type FROM ContactsUser  WHERE RegUserNo=contacts_getuserdata.reguserno AND Seq=contacts_getuserdata.userseq;

	ELSIF Key = 'deldate' THEN
		RETURN QUERY
		SELECT DelDate As Value ,0 AS Type FROM ContactsUser  WHERE RegUserNo=contacts_getuserdata.reguserno AND Seq=contacts_getuserdata.userseq;
	ELSIF Key = 'group' THEN
		RETURN QUERY
		SELECT G.GroupName As Value ,0 AS Type
		From ContactsGroupUser GU
		LEFT JOIN ContactsGroup G ON G.GroupNo = GU.GroupNo
		WHERE GU.RegUserNo = contacts_getuserdata.reguserno
		AND GU.UserSeq = contacts_getuserdata.userseq
		ORDER BY G.Sort;
	ELSE
		RETURN QUERY
		SELECT FirstName, LastName, CallName, Memo, Share FROM ContactsUser
		WHERE RegUserNo=contacts_getuserdata.reguserno and Seq=contacts_getuserdata.userseq;
		RETURN QUERY
		SELECT Type,TypeName,Value,IsDefault FROM ContactsNumber
		WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq AND Value != '';
		RETURN QUERY
		SELECT Value,IsDefault FROM ContactsEmail
		WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq;
		RETURN QUERY
		SELECT Type,TypeName,Value,IsDefault,SolarLunar FROM ContactsDays
		WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq;
		RETURN QUERY
		SELECT Company,Depart,Position,IsDefault FROM ContactsCompany
		WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq;
		RETURN QUERY
		SELECT Type,TypeName,ZipCode1,ZipCode2,Address,IsDefault FROM ContactsAddress
        WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq;
        RETURN QUERY
        SELECT Value,IsDefault FROM ContactsSns
        WHERE RegUserNo=contacts_getuserdata.reguserno AND UserSeq=contacts_getuserdata.userseq;
        RETURN QUERY
        SELECT G.GroupNo,GroupName FROM ContactsGroup G
        INNER JOIN ContactsGroupUser GU  ON G.GroupNo=GU.GroupNo
        WHERE GU.RegUserNo=contacts_getuserdata.reguserno and UserSeq=contacts_getuserdata.userseq;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserdatahistory
CREATE OR REPLACE FUNCTION public.contacts_getuserdatahistory(historyno integer, reguserno integer, userseq integer, key character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	IF Key = 'number' THEN
		RETURN QUERY
		SELECT Value, Type FROM ContactsNumberHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'email' THEN
		RETURN QUERY
		SELECT Value FROM ContactsEmailHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'days' THEN
		RETURN QUERY
		SELECT Value FROM ContactsDaysHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'comp' THEN
		RETURN QUERY
		SELECT Company FROM ContactsCompanyHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'dept' THEN
		RETURN QUERY
		SELECT Depart FROM ContactsCompanyHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'position' THEN
		RETURN QUERY
		SELECT Position FROM ContactsCompanyHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'addr' THEN
		RETURN QUERY
		SELECT '(' || ZipCode1 || '-' || ZipCode2 || ')' || Address Address FROM ContactsAddressHistory
        WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq AND IsDefault='1';

	ELSIF Key = 'sns' THEN
		RETURN QUERY
		SELECT Value FROM ContactsSnsHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq ORDER BY IsDefault DESC, Seq DESC;

	ELSIF Key = 'memo' THEN
		RETURN QUERY
		SELECT Memo FROM ContactsUserHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND Seq=contacts_getuserdatahistory.userseq;

	ELSIF Key = 'firstname' THEN
		RETURN QUERY
		SELECT FirstName FROM ContactsUserHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND Seq=contacts_getuserdatahistory.userseq;

	ELSIF Key = 'lastname' THEN
		RETURN QUERY
		SELECT LastName FROM ContactsUserHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND Seq=contacts_getuserdatahistory.userseq;

	ELSIF Key = 'callname' THEN
		RETURN QUERY
		SELECT CallName FROM ContactsUserHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND Seq=contacts_getuserdatahistory.userseq;

	ELSIF Key = 'deldate' THEN
		RETURN QUERY
		SELECT DelDate FROM ContactsUserHistory WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND Seq=contacts_getuserdatahistory.userseq;
	ELSIF Key = 'group' THEN
		RETURN QUERY
		SELECT G.GroupName
		From ContactsGroupUserHistory GU
		LEFT JOIN ContactsGroup G ON G.GroupNo = GU.GroupNo
		WHERE HistoryNo=contacts_getuserdatahistory.historyno
		AND GU.RegUserNo = contacts_getuserdatahistory.reguserno
		AND GU.UserSeq = contacts_getuserdatahistory.userseq
		ORDER BY G.Sort;
	ELSE
		RETURN QUERY
		SELECT FirstName, LastName, CallName, Memo, Share FROM ContactsUserHistory
		WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno and Seq=contacts_getuserdatahistory.userseq;

		RETURN QUERY
		SELECT Type,TypeName,Value,IsDefault FROM ContactsNumberHistory
		WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq AND Value != '';

		RETURN QUERY
		SELECT Value,IsDefault FROM ContactsEmailHistory
		WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq;

		RETURN QUERY
		SELECT Type,TypeName,Value,IsDefault,SolarLunar FROM ContactsDaysHistory
		WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq;

		RETURN QUERY
		SELECT Company,Depart,Position,IsDefault FROM ContactsCompanyHistory
		WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq;

		RETURN QUERY
		SELECT Type,TypeName,ZipCode1,ZipCode2,Address,IsDefault FROM ContactsAddressHistory
        WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq;

        RETURN QUERY
        SELECT Value,IsDefault FROM ContactsSnsHistory
        WHERE HistoryNo=contacts_getuserdatahistory.historyno AND RegUserNo=contacts_getuserdatahistory.reguserno AND UserSeq=contacts_getuserdatahistory.userseq;

        RETURN QUERY
        SELECT G.GroupNo,GroupName FROM ContactsGroup G
        INNER JOIN ContactsGroupUserHistory GU ON G.GroupNo=GU.GroupNo
        WHERE HistoryNo=contacts_getuserdatahistory.historyno AND GU.RegUserNo=contacts_getuserdatahistory.reguserno and UserSeq=contacts_getuserdatahistory.userseq;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getuserdetail
CREATE OR REPLACE FUNCTION public.contacts_getuserdetail(userseq integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	-- 주소;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Type,
	TypeName,
	ZipCode1,
	ZipCode2,
	Address,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsAddress WHERE UserSeq = contacts_getuserdetail.userseq;

	-- 회사;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Company,
	Depart,
	Position,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsCompany WHERE UserSeq = contacts_getuserdetail.userseq;

	-- 기념일;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Type,
	TypeName,
	Value,
	IsDefault,
	SolarLunar,
	RegDate,
	ModDate
	FROM ContactsDays WHERE UserSeq = contacts_getuserdetail.userseq;

	-- 이메일;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Value,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsEmail WHERE UserSeq = contacts_getuserdetail.userseq;

	-- 그룹;
	RETURN QUERY
	SELECT G.* FROM ContactsGroupUser U
	INNER JOIN ContactsGroup G ON G.GroupNo = U.GroupNo
	WHERE U.UserSeq=contacts_getuserdetail.userseq;

	-- 홈페이지;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Type,
	TypeName,
	Value,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsHomepage WHERE UserSeq = contacts_getuserdetail.userseq;

	-- 전화번호;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Type,
	TypeName,
	Value,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsNumber WHERE UserSeq = contacts_getuserdetail.userseq;

	-- SNS;
	RETURN QUERY
	SELECT
	Seq,
	RegUserNo,
	UserSeq,
	Type,
	TypeName,
	Value,
	IsDefault,
	RegDate,
	ModDate
	FROM ContactsSns WHERE UserSeq = contacts_getuserdetail.userseq;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroup
CREATE OR REPLACE FUNCTION public.contacts_getusergroup(reguserno integer, userno integer, groupno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    groupname character varying;
    groupcount integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN




	IF GroupNo = 0 THEN
		SELECT b.GroupName INTO groupname FROM ContactsGroupUser a
		INNER JOIN ContactsGroup b ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup.userno AND a.RegUserNo=contacts_getusergroup.reguserno;
	ELSE
		SELECT b.GroupName INTO groupname FROM ContactsGroupUser a
		INNER JOIN ContactsGroup b ON a.GroupNo=b.GroupNo
		WHERE a.UserSeq=contacts_getusergroup.userno AND a.RegUserNo=contacts_getusergroup.reguserno AND a.GroupNo IN (select TreeID from public."GetChildGroup"(RegUserNo,GroupNo));
	END IF;

	SELECT COUNT(*) INTO groupcount FROM ContactsGroupUser
	WHERE UserSeq=contacts_getusergroup.userno AND RegUserNo=contacts_getusergroup.reguserno;

	IF GroupCount = 1 THEN
		RETURN QUERY
		SELECT COALESCE(GroupName,'');
	ELSE
		RETURN QUERY
		SELECT COALESCE(GroupName,'') || ';' || CAST(GroupCount - 1 AS text);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupbylanguage
CREATE OR REPLACE FUNCTION public.contacts_getusergroupbylanguage(reguserno integer DEFAULT 70, langcode character varying DEFAULT 'EN'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH RECURSIVE ContactsGroups AS (
		  SELECT CGP.GroupNo,CGP.GroupNo AS RootGourpNo
		  FROM ContactsGroup CGP
		  WHERE CGP.UseYn='Y'
		  UNION ALL
		  SELECT CGC.GroupNo,C.RootGourpNo
		  FROM ContactsGroup CGC
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo AND CGC.UseYn='Y'
	)
	SELECT GroupNo, CASE WHEN STRPOS(GroupName, '{')>0 THEN (SELECT StringValue FROM ParseJson(GroupName)  WHERE NAME=contacts_getusergroupbylanguage.langcode) ELSE GroupName END AS  GroupName, RegUserNo, RegDate, Memo, COALESCE(ParentGNo,0) AS ParentGNo, Sort, IsDefault,
	(
		SELECT COUNT(*)
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq
		WHERE U.UseYn='Y' AND C.GroupNo IN (SELECT GroupNo FROM ContactsGroups WHERE RootGourpNo=CG.GroupNo)
	) AS UserCount,
	UseYn
	FROM ContactsGroup CG
	WHERE CG.RegUserNo=contacts_getusergroupbylanguage.reguserno AND CG.UseYn='Y'
	ORDER BY CG.Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupbyuserno
CREATE OR REPLACE FUNCTION public.contacts_getusergroupbyuserno(reguserno integer DEFAULT 70)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH RECURSIVE ContactsGroups AS (
		  SELECT CGP.GroupNo,CGP.GroupNo AS RootGourpNo
		  FROM ContactsGroup CGP
		  WHERE CGP.UseYn='Y'
		  UNION ALL
		  SELECT CGC.GroupNo,C.RootGourpNo
		  FROM ContactsGroup CGC
		  INNER JOIN ContactsGroups C ON CGC.ParentGNo = C.GroupNo AND CGC.UseYn='Y'
	)
	SELECT GroupNo, GroupName, RegUserNo, RegDate, Memo, COALESCE(ParentGNo,0) AS ParentGNo, Sort, IsDefault,
	(
		SELECT COUNT(*)
		FROM ContactsGroupUser C
		INNER JOIN ContactsUser U ON U.Seq = C.UserSeq
		WHERE U.UseYn='Y' AND C.GroupNo IN (SELECT GroupNo FROM ContactsGroups WHERE RootGourpNo=CG.GroupNo)
	) AS UserCount,
	UseYn
	FROM ContactsGroup CG
	WHERE CG.RegUserNo=contacts_getusergroupbyuserno.reguserno AND CG.UseYn='Y'
	ORDER BY CG.Sort;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_getusergroupmobi
CREATE OR REPLACE FUNCTION public.contacts_getusergroupmobi(reguser integer, groupid integer, currpage integer DEFAULT 1, recodperpage integer DEFAULT 20)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	WITH RECURSIVE s AS (
			SELECT ROW_NUMBER()
				OVER(ORDER BY CG.UserSeq DESC) AS RowNum,CG.UserSeq ,
				(SELECT COUNT(*) FROM ContactsGroupUser CG INNER JOIN ContactsUser CU ON CG.UserSeq=CU.Seq
					WHERE CG.RegUserNo=contacts_getusergroupmobi.reguser
						  AND CG.GroupNo=contacts_getusergroupmobi.groupid
						  AND CU.UseYn='Y') as counts
			FROM ContactsGroupUser CG
			INNER JOIN ContactsUser CU
			ON CG.UserSeq=CU.Seq
			WHERE CG.RegUserNo=contacts_getusergroupmobi.reguser
				  AND CG.GroupNo=contacts_getusergroupmobi.groupid
				  AND CU.UseYn='Y'
		)
		Select * From s
		Where RowNum Between
			(currPage - 1)*recodperpage+1
			AND currPage*recodperpage;
END;
$function$


