					CompanyCntUp := CompanyCntUp + 1;
					TempCompanyUp := SUBSTRING(TempCompanyUp,STRPOS(TempCompanyUp, ',')+1,LEN(TempCompanyUp));
				END LOOP;
				PositionUp := TempCompanyUp;
