					DepartUp,
					PositionUp
				);
				CompanyInfo := SUBSTRING(CompanyInfo,STRPOS(CompanyInfo, '$')+1,LEN(CompanyInfo));
			END LOOP;
			INSERT INTO ContactsCompany
			(
