-- OBJECT ROUTINE public/dbo.contacts_savecontactshistory
CREATE OR REPLACE FUNCTION public.contacts_savecontactshistory(userno integer, seq integer, status character varying DEFAULT 'DEL'::character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    historyno integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	-- 주소록 메인;
	INSERT INTO ContactsUserHistory
	(
		Seq, FirstName, LastName, RegUserNo, Memo,
		RegDate, Photo, ModDate, CheckDate, Share,
		UseYn, DelDate, Important, CallName, ViewCount,
		Status
	)
	SELECT
		Seq, FirstName,LastName,RegUserNo, Memo,
		RegDate, Photo, NOW(), CheckDate, Share,
		UseYn, DelDate, Important, CallName, ViewCount,
		Status
	FROM ContactsUser
	WHERE RegUserNo=contacts_savecontactshistory.userno AND Seq=contacts_savecontactshistory.seq;

	HistoryNo := lastval();
	-- 전화번호 기록;
	INSERT INTO ContactsNumberHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, NOW()
	FROM ContactsNumber
	WHERE RegUserNo=contacts_savecontactshistory.userno AND UserSeq = contacts_savecontactshistory.seq;
	-- 이메일 이력;
	INSERT INTO ContactsEmailHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Value,
		IsDefault, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Value,
		IsDefault, RegDate, NOW()
	FROM ContactsEmail
	WHERE RegUserNo = contacts_savecontactshistory.userno AND UserSeq = contacts_savecontactshistory.seq;
	-- 기념일 이력;
	INSERT INTO ContactsDaysHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, SolarLunar, RegDate,
		ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, SolarLunar, RegDate,
		NOW()
	FROM ContactsDays
	WHERE RegUserNo = contacts_savecontactshistory.userno AND UserSeq = contacts_savecontactshistory.seq;
	-- 회사;
	INSERT INTO ContactsCompanyHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Company,
		Depart, Position, IsDefault, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Company,
		Depart, Position, IsDefault, RegDate, NOW()
	FROM ContactsCompany
	WHERE RegUserNo = contacts_savecontactshistory.userno AND UserSeq = contacts_savecontactshistory.seq;
	-- 주소;
	INSERT INTO ContactsAddressHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, ZipCode1, ZipCode2, Address, IsDefault,
		RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, ZipCode1, ZipCode2, Address, IsDefault,
		RegDate, NOW()
	FROM ContactsAddress
	WHERE RegUserNo = contacts_savecontactshistory.userno ANd UserSeq = contacts_savecontactshistory.seq;
	-- 홈페이지;
	INSERT INTO ContactsHomepageHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	FROM ContactsHomepage
	WHERE RegUserNo = contacts_savecontactshistory.userno AND UserSeq = contacts_savecontactshistory.seq;
	-- SNS;
	INSERT INTO ContactsSnsHistory
	(
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, RegUserNo, UserSeq, Type,
		TypeName, Value, IsDefault, RegDate, NOW()
	FROM ContactsSns
	WHERE RegUserNo = contacts_savecontactshistory.userno ANd UserSeq = contacts_savecontactshistory.seq;

	-- 그룹;
	INSERT INTO ContactsGroupUserHistory
	(
		HistoryNo, Seq, GroupNo, UserSeq, RegUserNo, RegDate, ModDate
	)
	SELECT
		HistoryNo, Seq, GroupNo, UserSeq, RegUserNo, RegDate, NOW()
	FROM ContactsGroupUser
	WHERE RegUserNo = contacts_savecontactshistory.userno ANd UserSeq = contacts_savecontactshistory.seq;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savegroupforoutlook
CREATE OR REPLACE FUNCTION public.contacts_savegroupforoutlook(userno integer, outlookentryid character varying, groupname character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    groupno integer;
    groupcount integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN




	SELECT COUNT(GroupNo) INTO groupcount FROM ContactsGroupOutlook

	WHERE UserNo = contacts_savegroupforoutlook.userno
	AND OutlookFolderEntryID = contacts_savegroupforoutlook.outlookentryid;

	IF GroupCount = 0 THEN
		INSERT INTO ContactsGroup
		(
			RegDate,
			RegUserNo,
			ParentGNo,
			GroupName,
			IsDefault,
			Memo,
			Sort
		)
		VALUES
		(
			NOW(),
			UserNo,
			0,
			GroupName,
			1,
			'아웃룩',
			(SELECT COALESCE(MAX(Sort),0)+1 FROM ContactsGroup WHERE RegUserNo = contacts_savegroupforoutlook.userno)
		);

		GroupNo := lastval();
		INSERT INTO ContactsGroupOutlook
		(
			UserNo,
			GroupNo,
			OutlookFolderEntryID
		)
		VALUES
		(
			UserNo,
			GroupNo,
			OutlookEntryID
		);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savelocation
CREATE OR REPLACE FUNCTION public.contacts_savelocation(userno integer, name character varying, latitude double precision, longitude double precision, errorrange integer, description character varying, contactuserid integer, locationno integer DEFAULT 0)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF LocationNo = 0 THEN
		INSERT INTO Contacts_Locations
			   (RegUserNo
			   ,RegDate
			   ,ModUserNo
			   ,ModDate
			   ,Name
			   ,Latitude
			   ,Longitude
			   ,ErrorRange
			   ,Description
			   ,ContactUserId)
		 VALUES
			   (UserNo
			   ,NOW()
			   ,UserNo
			   ,NOW()
			   ,Name
			   ,Latitude
			   ,Longitude
			   ,ErrorRange
			   ,Description
			   ,ContactUserId
			   );
	ELSE
		UPDATE Contacts_Locations
		   SET
			  ModUserNo = contacts_savelocation.userno
			  ,ModDate = NOW()
			  ,Name = contacts_savelocation.name
			  ,Latitude = contacts_savelocation.latitude
			  ,Longitude = contacts_savelocation.longitude
			  ,ErrorRange = contacts_savelocation.errorrange
			  ,Description = contacts_savelocation.description
			  ,ContactUserId=contacts_savelocation.contactuserid

		 WHERE LocationNo = contacts_savelocation.locationno;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_saverestore
CREATE OR REPLACE FUNCTION public.contacts_saverestore(historynolist character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    temphistoryno integer;
    chkhistoryno character varying;
    tempseq integer;
    datacount integer;
    newseq integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN



	HistoryNoList := contacts_saverestore.historynolist || ',';
	ChkHistoryNo := REPLACE(HistoryNoList,',','');
	IF LEN(ChkHistoryNo) > 0 THEN

		WHILE STRPOS(HistoryNoList, ',') > 0 LOOP
			TempHistoryNo := SUBSTRING(HistoryNoList,0,STRPOS(HistoryNoList, ','));
			SELECT Seq INTO tempseq FROM ContactsUserHistory WHERE HistoryNo = TempHistoryNo;



			SELECT COUNT(Seq) INTO datacount FROM ContactsUser WHERE Seq = TempSeq;
			-- 데이터가 없으면 신규입력
			IF DataCount = 0 THEN

				-- 주소록 기본 정보;
				INSERT INTO ContactsUser
				(
					FirstName, LastName, RegUserNo, Memo, RegDate,
					Photo, ModDate, CheckDate, Share, UseYn,
					DelDate, Important, CallName, ViewCount
				)
				SELECT FirstName, LastName, RegUserNo, Memo, RegDate,
					Photo, ModDate, CheckDate, Share, UseYn,
					DelDate, Important, CallName, ViewCount
				FROM ContactsUserHistory WHERE HistoryNo = TempHistoryNo;

				newSeq := lastval();
				-- 전화번호;
				INSERT INTO ContactsNumber
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsNumberHistory WHERE HistoryNo = TempHistoryNo;
				-- 이메일;
				INSERT INTO ContactsEmail
				(
					RegUserNo, UserSeq, Value, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Value, IsDefault, RegDate, NOW()
				FROM ContactsEmailHistory WHERE HistoryNo = TempHistoryNo;
				-- 회사;
				INSERT INTO ContactsCompany
				(
					RegUserNo, UserSeq, Company, Depart, Position,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Company, Depart, Position,
					IsDefault, RegDate, NOW()
				FROM ContactsCompanyHistory WHERE HistoryNo = TempHistoryNo;
				-- 주소;
				INSERT INTO ContactsAddress
				(
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, NOW()
				FROM ContactsAddressHistory WHERE HistoryNo = TempHistoryNo;

				-- 홈페이지;
				INSERT INTO ContactsHomepage
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsHomepageHistory WHERE HistoryNo = TempHistoryNo;
				-- SNS;
				INSERT INTO ContactsSns
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, newSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsSnsHistory WHERE HistoryNo = TempHistoryNo;
				-- 그룹;
				INSERT INTO ContactsGroupUser
				(
					GroupNo, UserSeq, RegUserNo, RegDate, ModDate
				)
				SELECT
					GroupNo, newSeq, RegUserNo, RegDate, ModDate
				FROM ContactsGroupUserHistory WHERE HistoryNo = TempHistoryNo;
			ELSE
				UPDATE U
				SET FirstName = H.FirstName,
					LastName = H.LastName,
					RegDate = H.RegDate,
					Memo = H.Memo,
					RegUserNo = H.RegUserNo,
					Photo = H.Photo,
					ModDate = NOW(),
					CheckDate = H.CheckDate,
					Share = H.Share,
					UseYn = 'Y',
					DelDate = H.DelDate,
					Important = H.Important,
					CallName = H.CallName,
					ViewCount = H.ViewCount
				FROM ContactsUser U, ContactsUserHistory H
				WHERE U.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;
				-- #################
				-- 전화번호
				-- #################
					-- Seq랑 일치 하는 않는거 삭제;
				DELETE FROM ContactsNumber
				WHERE Seq NOT IN (SELECT Seq FROM ContactsNumberHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;
					-- Seq랑 일치 하는거 업데이트;
				UPDATE N
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsNumber N, ContactsNumberHistory H
				WHERE N.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;
					-- 그외 히스토리에 있는거 인서트;
				INSERT INTO ContactsNumber
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, NOW()
				FROM ContactsNumberHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsNumber WHERE UserSeq = TempSeq);
				-- #################
				-- 이메일
				-- #################;
				DELETE FROM ContactsEmail
				WHERE Seq NOT IN (SELECT Seq FROM ContactsEmailHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE E
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsEmail E, ContactsEmailHistory H
				WHERE E.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsEmail
				(
					RegUserNo, UserSeq, Value, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Value, IsDefault, RegDate, NOW()
				FROM ContactsEmailHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsEmail WHERE UserSeq = TempSeq);
				-- #################
				-- 회사
				-- #################;
				DELETE FROM ContactsCompany
				WHERE Seq NOT IN (SELECT Seq FROM ContactsCompanyHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE C
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Company = H.Company,
					Depart = H.Depart,
					Position = H.Position,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsCompany C, ContactsCompanyHistory H
				WHERE C.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsCompany
				(
					RegUserNo, UserSeq, Company, Depart, Position,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Company, Depart, Position,
					IsDefault, RegDate, ModDate
				FROM ContactsCompanyHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsCompany WHERE UserSeq = TempSeq);
				-- #################
				-- 주소
				-- #################;
				DELETE FROM ContactsAddress
				WHERE Seq NOT IN (SELECT Seq FROM ContactsAddressHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE A
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					ZipCode1 = H.ZipCode1,
					ZipCode2 = H.ZipCode2,
					Address = H.Address,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsAddress A, ContactsAddressHistory H
				WHERE A.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsAddress
				(
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, ZipCode1,
					ZipCode2, Address, IsDefault, RegDate, ModDate
				FROM ContactsAddressHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsAddress WHERE UserSeq = TempSeq);
				-- #################
				-- 홈페이지
				-- #################;
				DELETE FROM ContactsHomepage
				WHERE Seq NOT IN (SELECT Seq FROM ContactsHomepageHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE P
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsHomepage P, ContactsHomepageHistory H
				WHERE P.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsHomepage
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				FROM ContactsHomepageHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsHomepage WHERE UserSeq = TempSeq);
				-- #################
				-- SNS
				-- #################;
				DELETE FROM ContactsSns
				WHERE Seq NOT IN (SELECT Seq FROM ContactsSnsHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE S
				SET RegUserNo = H.RegUserNo,
					UserSeq = H.UserSeq,
					Type = H.Type,
					TypeName = H.TypeName,
					Value = H.Value,
					IsDefault = H.IsDefault,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsSns S, ContactsSnsHistory H
				WHERE S.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsSns
				(
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				)
				SELECT
					RegUserNo, UserSeq, Type, TypeName, Value,
					IsDefault, RegDate, ModDate
				FROM ContactsSnsHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsSns WHERE UserSeq = TempSeq);
				-- #################
				-- 그룹
				-- #################;
				DELETE FROM ContactsGroupUser
				WHERE Seq NOT IN (SELECT Seq FROM ContactsGroupUserHistory WHERE HistoryNo = TempHistoryNo)
				AND UserSeq = TempSeq;

				UPDATE G
				SET GroupNo = H.GroupNo,
					UserSeq = H.UserSeq,
					RegUserNo = H.RegUserNo,
					RegDate = H.RegDate,
					ModDate = NOW()
				FROM ContactsGroupUser G, ContactsGroupUserHistory H
				WHERE G.Seq = H.Seq
				AND H.HistoryNo = TempHistoryNo;

				INSERT INTO ContactsGroupUser
				(
					GroupNo, UserSeq, RegUserNo, RegDate, ModDate
				)
				SELECT
					GroupNo, UserSeq, RegUserNo, RegDate, NOW()
				FROM ContactsGroupUserHistory
				WHERE HistoryNo = TempHistoryNo
				AND Seq NOT IN (SELECT Seq FROM ContactsGroupUser WHERE UserSeq = TempSeq);

			END IF;

			DELETE FROM ContactsNumberHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsEmailHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsDaysHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsCompanyHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsAddressHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsSnsHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsGroupUserHistory WHERE HistoryNo = TempHistoryNo;
			DELETE FROM ContactsUserHistory WHERE HistoryNo = TempHistoryNo;

			HistoryNoList := SUBSTRING(HistoryNoList,STRPOS(HistoryNoList, ',')+1,LEN(HistoryNoList));
		END LOOP;
		IF 0 <> 0 THEN

		END IF;

	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_savesetup
CREATE OR REPLACE FUNCTION public.contacts_savesetup(userno integer, pagesize integer, startcontactboxno bigint, isfolderexpanded boolean)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    cnt integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN



	SELECT COUNT(UserNo) INTO cnt FROM ContactsSetup WHERE UserNo = contacts_savesetup.userno;

	IF CNT = 0 THEN
		INSERT INTO ContactsSetup
		(
			UserNo,
			RegUserNo,
			RegDate,
			ModUserNo,
			ModDate,
			PageSize,
			StartContactBoxNo,
			IsFolderExpanded
		)
		VALUES
		(
			UserNo,
			UserNo,
			NOW(),
			UserNo,
			NOW(),
			PageSize,
			StartContactBoxNo,
			IsFolderExpanded
		);
	ELSE

		UPDATE ContactsSetup
		SET
			ModUserNo = contacts_savesetup.userno,
			ModDate = NOW(),
			PageSize = contacts_savesetup.pagesize,
			StartContactBoxNo = contacts_savesetup.startcontactboxno,
			IsFolderExpanded = contacts_savesetup.isfolderexpanded
		WHERE UserNo = contacts_savesetup.userno;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_search_nodistance
CREATE OR REPLACE FUNCTION public.contacts_search_nodistance(userno integer, serchtype integer, serchtext character varying, viewcount integer, currentpageindex integer, sortcolumn character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF SerchType=21 THEN
		RETURN QUERY
		SELECT * FROM (SELECT
				CONVERT(INT,COUNT(*) OVER()) AS TotalCnt
				,CONVERT(INT, ROW_NUMBER() OVER (
				ORDER BY
					CASE WHEN SortColumn='ASC_NAME' THEN U.LastName END ASC,
					CASE WHEN SortColumn='DESC_NAME' THEN U.LastName END DESC,
					CASE WHEN SortColumn='ASC_COMPANY' THEN C.Company END ASC,
					CASE WHEN SortColumn='DESC_COMPANY' THEN C.Company END DESC,
					CASE WHEN SortColumn='ASC_DEPART' THEN C.Depart END ASC,
					CASE WHEN SortColumn='DESC_DEPART' THEN C.Depart END DESC
				)) AS RowNum
				,C.Company
				,C.Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				FROM (SELECT * FROM ContactsUser WHERE RegUserNo=contacts_search_nodistance.userno AND UseYn='Y') U
				LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
				LEFT JOIN (SELECT * FROM ContactsAddress WHERE RegUserNo=contacts_search_nodistance.userno) A ON A.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsCompany WHERE RegUserNo=contacts_search_nodistance.userno) C ON C.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsDays WHERE RegUserNo=contacts_search_nodistance.userno) D ON D.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsEmail WHERE RegUserNo=contacts_search_nodistance.userno) E ON E.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsHomepage WHERE RegUserNo=contacts_search_nodistance.userno) H ON H.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsNumber WHERE RegUserNo=contacts_search_nodistance.userno) N ON N.UserSeq=U.Seq
				LEFT JOIN (SELECT * FROM ContactsSns WHERE RegUserNo=contacts_search_nodistance.userno) S ON S.UserSeq=U.Seq
				WHERE
				U.Seq not in (SELECT ContactUserId FROM Contacts_Locations CL WHERE CL.RegUserNo=contacts_search_nodistance.userno ) AND
				((U.LastName || ' ' || U.FirstName) ILIKE '%' || SerchText || '%' or (U.FirstName || ' ' || U.LastName) ILIKE '%' || SerchText || '%'  or C.Company ILIKE '%' || SerchText || '%' or C.Depart ILIKE '%' || SerchText || '%' or C.Position ILIKE '%' || SerchText || '%' or E.Value ILIKE '%' || SerchText || '%' or (SELECT GroupName FROM ContactsGroup WHERE G.GroupNo=GroupNo) ILIKE '%' || SerchText || '%' or A.Address ILIKE '%' || SerchText || '%')

				GROUP BY
				C.Company
				,C.Depart
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				) T
				WHERE T.RowNum
				BETWEEN ((CurrentPageIndex - 1) * ViewCount) + 1
				AND CurrentPageIndex * ViewCount;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_searchmobi
CREATE OR REPLACE FUNCTION public.contacts_searchmobi(userno integer, serchtext character varying, type integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT * FROM (SELECT
				CONVERT(INT,COUNT(*) OVER()) AS TotalCnt
				,CONVERT(INT, ROW_NUMBER() OVER (
				ORDER BY
					U.LastName ASC
				)) AS RowNum
				,U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				FROM (SELECT * FROM ContactsUser WHERE RegUserNo=contacts_searchmobi.userno AND UseYn='Y') U
				LEFT JOIN ContactsGroupUser G ON G.UserSeq = U.Seq
				LEFT JOIN ContactsNumber CN ON CN.UserSeq=U.Seq
				WHERE U.Seq IN (SELECT MAX(Seq) FROM ContactsUser WHERE RegUserNo=contacts_searchmobi.userno GROUP BY (FirstName+LastName)) AND
				((U.LastName || ' ' || U.FirstName) ILIKE '%' || SerchText || '%' or (U.FirstName || ' ' || U.LastName) ILIKE '%' || SerchText || '%' or CN.Value ILIKE '%' || SerchText || '%')

				GROUP BY
				U.Seq
				,U.FirstName
				,U.LastName
				,U.RegUserNo
				,U.Memo
				,U.RegDate
				,U.Photo
				,U.ModDate
				,U.CheckDate
				,U.Share
				,U.UseYn
				,U.DelDate
				,U.Important
				,U.CallName
				) T;
END;
$function$


