-- OBJECT ROUTINE public/dbo.contacts_setaddress
CREATE OR REPLACE FUNCTION public.contacts_setaddress(reguserno integer, userseq integer, type smallint, typename character varying, zipcode1 character varying, zipcode2 character varying, address character varying, isdefault character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF Address IS NOT NULL THEN
		IF LEN(Address) > 0 THEN
			INSERT INTO ContactsAddress(RegUserNo,UserSeq,Type,TypeName,ZipCode1,ZipCode2,Address,IsDefault)
			VALUES(RegUserNo,UserSeq,Type,TypeName,ZipCode1,ZipCode2,Address,IsDefault);
		END IF;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_setcallphone
CREATE OR REPLACE FUNCTION public.contacts_setcallphone(seq integer)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	UPDATE ContactsNumber
	SET SetCall=1
	WHERE Seq=contacts_setcallphone.seq;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_setcompany
CREATE OR REPLACE FUNCTION public.contacts_setcompany(reguserno integer, userseq integer, company character varying, depart character varying, "position" character varying, isdefault character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	IF Company IS NOT NULL OR Depart IS NOT NULL OR Position IS NOT NULL THEN
		INSERT INTO ContactsCompany(RegUserNo,UserSeq,Company,Depart,Position,IsDefault)
		VALUES(RegUserNo,UserSeq,Company,Depart,Position,IsDefault);
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_setcontactsgroup
CREATE OR REPLACE FUNCTION public.contacts_setcontactsgroup(groupno integer, groupname character varying, reguserno integer, memo character varying, mode character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    sort integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	IF Mode = '0' THEN

		SELECT COUNT(*) + 1 INTO sort FROM ContactsGroup WHERE RegUserNo=contacts_setcontactsgroup.reguserno AND ParentGNo=contacts_setcontactsgroup.groupno;

		INSERT INTO ContactsGroup(GroupName, RegUserNo, RegDate, Memo,ParentGNo,Sort, IsDefault)
		VALUES(GroupName, RegUserNo, NOW(), Memo, GroupNo, Sort , '0');
	ELSIF Mode = '1' THEN
		UPDATE ContactsGroup SET GroupName=contacts_setcontactsgroup.groupname WHERE GroupNo=contacts_setcontactsgroup.groupno;
	ELSE
		UPDATE ContactsGroup SET Memo=contacts_setcontactsgroup.memo WHERE GroupNo=contacts_setcontactsgroup.groupno;
	END IF;
END;
$function$


-- OBJECT ROUTINE public/dbo.contacts_setcontactsrestore
CREATE OR REPLACE FUNCTION public.contacts_setcontactsrestore(reguserno integer, userno character varying, groupno character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

	UPDATE ContactsUser SET UseYn='Y' WHERE Seq=contacts_setcontactsrestore.userno AND RegUserNo=contacts_setcontactsrestore.reguserno;
	UPDATE ContactsGroupUser SET GroupNo=contacts_setcontactsrestore.groupno WHERE UserSeq=contacts_setcontactsrestore.userno AND RegUserNo=contacts_setcontactsrestore.reguserno;
END;
$function$


