-- OBJECT ROUTINE public/dbo.crewchat_getchatroomtitle
CREATE OR REPLACE FUNCTION public.crewchat_getchatroomtitle(roomno bigint, userno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
