-- OBJECT ROUTINE public/dbo.eappdocument_update
CREATE OR REPLACE FUNCTION public.eappdocument_update(id integer, agreemanagerid character varying, title character varying DEFAULT NULL::character varying, content text DEFAULT NULL::text, writerid character varying DEFAULT NULL::character varying, positionid character varying DEFAULT NULL::character varying, departid character varying DEFAULT NULL::character varying, gradeid character varying DEFAULT NULL::character varying, worder integer DEFAULT NULL::integer, wlevel integer DEFAULT NULL::integer, wgroup integer DEFAULT NULL::integer, isnotice character varying DEFAULT NULL::character varying, lcategory character varying DEFAULT NULL::character varying, scategory character varying DEFAULT NULL::character varying, authoritylevel integer DEFAULT NULL::integer, issecret character varying DEFAULT NULL::character varying, hit integer DEFAULT NULL::integer, regdate timestamp without time zone DEFAULT NULL::timestamp without time zone, modifier character varying DEFAULT NULL::character varying, moddate timestamp without time zone DEFAULT NULL::timestamp without time zone, valdate timestamp without time zone DEFAULT NULL::timestamp without time zone, isdelete character varying DEFAULT NULL::character varying, description character varying DEFAULT NULL::character varying, pathid integer DEFAULT NULL::integer, progid integer DEFAULT NULL::integer, state integer DEFAULT NULL::integer, formid integer DEFAULT NULL::integer, serial character varying DEFAULT NULL::character varying, operationdate character varying DEFAULT NULL::character varying, storeperiod integer DEFAULT NULL::integer, contentid integer DEFAULT NULL::integer, totalstoredboxid integer DEFAULT NULL::integer, historyid integer DEFAULT NULL::integer, erpkey character varying DEFAULT NULL::character varying, docsign character varying DEFAULT NULL::character varying, agreeorder integer DEFAULT NULL::integer, duty character varying DEFAULT NULL::character varying, drafter character varying DEFAULT NULL::character varying, rootid integer DEFAULT NULL::integer, summary text DEFAULT NULL::text, contenttext character varying DEFAULT NULL::character varying, opiniontext character varying DEFAULT NULL::character varying, filenametext text DEFAULT NULL::text, groupcode character varying DEFAULT NULL::character varying, isdraftdel character varying DEFAULT NULL::character varying, operationtype integer DEFAULT NULL::integer, edmsid integer DEFAULT NULL::integer, edmsstate integer DEFAULT NULL::integer, isclose character varying DEFAULT NULL::character varying, agreedocid integer DEFAULT NULL::integer, deptname1 character varying DEFAULT NULL::character varying, deptname2 character varying DEFAULT NULL::character varying, deptname3 character varying DEFAULT NULL::character varying, deptname4 character varying DEFAULT NULL::character varying, isautoafter character varying DEFAULT NULL::character varying)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN

UPDATE public."EAPPDocument" SET
	  Title = COALESCE(Title, Title)
	, Content = COALESCE(Content, Content)
	, WriterID = COALESCE(WriterID, WriterID)
	, PositionID = COALESCE(PositionID, PositionID)
	, DepartID = COALESCE(DepartID, DepartID)
	, GradeID = COALESCE(GradeID, GradeID)
	, WOrder = COALESCE(WOrder, WOrder)
	, WLevel = COALESCE(WLevel, WLevel)
	, WGroup = COALESCE(WGroup, WGroup)
	, IsNotice = COALESCE(IsNotice, IsNotice)
	, LCategory = COALESCE(LCategory, LCategory)
	, SCategory = COALESCE(SCategory, SCategory)
	, AuthorityLevel = COALESCE(AuthorityLevel, AuthorityLevel)
	, IsSecret = COALESCE(IsSecret, IsSecret)
	, Hit = COALESCE(Hit, Hit)
	, RegDate = COALESCE(RegDate, RegDate)
	, Modifier = COALESCE(Modifier, Modifier)
	, ModDate = COALESCE(ModDate, ModDate)
	, ValDate = COALESCE(ValDate, ValDate)
	, IsDelete = COALESCE(IsDelete, IsDelete)
	, Description = COALESCE(Description, Description)
	, PathID = COALESCE(PathID, PathID)
	, ProgID = COALESCE(ProgID, ProgID)
	, State = COALESCE(State, State)
	, FormID = COALESCE(FormID, FormID)
	, Serial = COALESCE(Serial, Serial)
	, OperationDate = COALESCE(OperationDate, OperationDate)
	, StorePeriod = COALESCE(StorePeriod, StorePeriod)
	, ContentID = COALESCE(ContentID, ContentID) 
	, TotalStoredBoxID = COALESCE(TotalStoredBoxID, TotalStoredBoxID)
	, HistoryID = COALESCE(HistoryID, HistoryID)
	, ErpKey = COALESCE(ErpKey, ErpKey)
	, DocSign = COALESCE(DocSign, DocSign)
	, AgreeOrder = COALESCE(AgreeOrder, AgreeOrder)
	, Duty = COALESCE(Duty, Duty)
	, Drafter = COALESCE(Drafter, Drafter)
	, RootID = COALESCE(RootID, RootID)
	, Summary = COALESCE(Summary, Summary)
	, ContentText = COALESCE(ContentText, ContentText)
	, OpinionText = COALESCE(OpinionText, OpinionText)
	, FileNameText = COALESCE(FileNameText, FileNameText)
	, GroupCode = COALESCE(GroupCode, GroupCode)
	, IsDraftDel = COALESCE(IsDraftDel, IsDraftDel)
	, OperationType = COALESCE(OperationType, OperationType)
	, EDMSID = COALESCE(EDMSID, EDMSID)
	, EDMSState = COALESCE(EDMSState, EDMSState)
	, IsClose = COALESCE(IsClose, IsClose)
	,AgreeDocId= COALESCE(AgreeDocId, AgreeDocId)
	,AgreeManagerID = COALESCE(AgreeManagerID, AgreeManagerID)
	,DeptName1 = COALESCE(DeptName1, DeptName1)
	,DeptName2 = COALESCE(DeptName2, DeptName2)
	,DeptName3 = COALESCE(DeptName3, DeptName3)
	,DeptName4 = COALESCE(DeptName4, DeptName4)
	,IsAutoAfter= COALESCE(IsAutoAfter, IsAutoAfter)
	
WHERE ID = eappdocument_update.id;
END;
$function$


