						on p.DocumentID = d.id		
				where	((depart <> '%' and p.departid = depart) or (depart = '%' and p.departid ILIKE depart))
				GROUP BY MANAGERID
			)B
			ON c.userid = B.MANAGERID
	) DT;
END;
$function$


