-- OBJECT ROUTINE public/dbo.edmstreeauthoritylist
CREATE OR REPLACE FUNCTION public.edmstreeauthoritylist(folderid character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
DECLARE
    folderid integer;
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
	/*	test

FolderID := (1);
	--*/
	RETURN QUERY
	SELECT	E.DEPARTID
	,(case when LangIndex = 1  then D.Name
				when LangIndex=2 then D.Name_EN
				when LangIndex=3 then D.Name_EN
				when LangIndex=4 then D.Name_EN
			end)  AS DEPARTNAME
