-- OBJECT ROUTINE public/dbo.edmsuserlist
CREATE OR REPLACE FUNCTION public.edmsuserlist(orgcd character varying)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN
RETURN QUERY
select	a.UserId	
,		a.Name	as UserNm
,		''		as GrpNm
,		c.Name as OrgNm		
,		public."EDMSGetAuthorityLevelContents"(d.AuthorityLevel) AS AuthorityLevel
FROM	Organization_Users   A
		left join
  		Organization_BelongToDepartment	b
		on	A.USERNO=b.UserNo
		left JOIN
		Organization_Departments	c
		on	b.DepartNo = c.DepartNo
		left join
		edmsUserEnv d
		on	a.userid = d.userid 
WHERE	c.DepartNo ILIKE ORGCD
and		a.Enabled = '1';
END;
$function$


-- OBJECT ROUTINE public/dbo.func_datefromparts
CREATE OR REPLACE FUNCTION public.func_datefromparts(year integer, month integer, dayofmonth integer, hour integer DEFAULT 0, sec integer DEFAULT 0)
 RETURNS timestamp without time zone
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


    RETURN DATEADD(second, Sec, 
            DATEADD(minute, Min, 
            DATEADD(hour, Hour,
            DATEADD(day, DayOfMonth - 1, 
            DATEADD(month, Month - 1, 
            DATEADD(Year, Year-1900, 0))))));
END;
$function$


