-- OBJECT ROUTINE public/dbo.mail_getmailbccuser
CREATE OR REPLACE FUNCTION public.mail_getmailbccuser(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

       
       RETURN QUERY
       SELECT B.BccSettingNo,B.BccUserNo,U.UserID,U.Name,D.Name as DepartName , P.Name as PositionName, U.MailAddress
       FROM Mail_BccSetting B
	   INNER JOIN Organization_Users U ON B.BccUserNo = U.UserNo
	   INNER JOIN Organization_BelongToDepartment BB ON B.BccUserNo = BB.UserNo and BB.IsDefault = TRUE
	   INNER JOIN Organization_Departments D ON D.DepartNo = BB.DepartNo
	   INNER JOIN Organization_Positions P ON P.PositionNo = BB.PositionNo
       WHERE B.UserNo = mail_getmailbccuser.userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.mail_getmailbccuserlist
CREATE OR REPLACE FUNCTION public.mail_getmailbccuserlist()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

       
       RETURN QUERY
       select U.UserNo,U.UserID,U.Name,P.Name as PositionName,B.BccUserNoCount as BccSettingCount from (
	   SELECT UserNo,count(*) as BccUserNoCount
       FROM Mail_BccSetting
	   group by UserNo) B
	   INNER JOIN Organization_Users U ON B.UserNo = U.UserNo
	   INNER JOIN Organization_BelongToDepartment BB ON B.UserNo = BB.UserNo and BB.IsDefault = TRUE
	   INNER JOIN Organization_Departments D ON D.DepartNo = BB.DepartNo
	   INNER JOIN Organization_Positions P ON P.PositionNo = BB.PositionNo;
END;
$function$


