-- OBJECT ROUTINE public/dbo.note_getnotelistcount
CREATE OR REPLACE FUNCTION public.note_getnotelistcount(boxtype character varying, isread boolean DEFAULT true)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT 
		COUNT(NoteNo) AS CNT
	FROM NoteList N
	INNER JOIN NoteBox B ON N.UserNo = B.UserNo AND N.NoteBoxNo = B.NoteBoxNo
	WHERE N.UserNo = UserNo
	AND B.BoxType = note_getnotelistcount.boxtype
	AND (N.IsRead = note_getnotelistcount.isread OR 1=note_getnotelistcount.isread);
END;
$function$


