 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT 
		COUNT(NoteNo) AS CNT
	FROM NoteList N
	INNER JOIN NoteBox B ON N.UserNo = B.UserNo AND N.NoteBoxNo = B.NoteBoxNo
	WHERE N.UserNo = UserNo
	AND N.IsRead = FALSE
	AND B.BoxType = BoxType;
END;
$function$


