-- OBJECT ROUTINE public/dbo.noticesyn_getdepartments
CREATE OR REPLACE FUNCTION public.noticesyn_getdepartments()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
select DepartNo,ParentNo,(case when LangCode='EN' then Name_EN when LangCode='CH' then Name_CH when LangCode='JP' then Name_JP when LangCode='VN' then Name_VN else Name end) as Name
 from Organization_Departments where Enabled = TRUE;
END;
$function$


-- OBJECT ROUTINE public/dbo.noticesyn_getdepartments_paging
CREATE OR REPLACE FUNCTION public.noticesyn_getdepartments_paging(langcode character varying, currentpageindex integer, viewcount integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

RETURN QUERY
select * from (
select CONVERT(INT,COUNT(*) OVER()) AS Total, ROW_NUMBER() OVER (Order by DepartNo) AS RowNum, DepartNo,ParentNo,(case when LangCode='EN' then Name_EN when LangCode='CH' then Name_CH when LangCode='JP' then Name_JP when LangCode='VN' then Name_VN else Name end) as Name
 from Organization_Departments where Enabled = TRUE
 ) T
 where T.RowNum BETWEEN CONVERT(NVARCHAR(20), ((CurrentPageIndex - 1) * ViewCount) + 1) AND CONVERT(NVARCHAR(20), CurrentPageIndex * ViewCount);
END;
$function$


