-- OBJECT ROUTINE public/dbo.organization_updatecommongroup_name
CREATE OR REPLACE FUNCTION public.organization_updatecommongroup_name(groupno bigint, moduserno integer, moddate timestamp without time zone)
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN


	UPDATE Organization_CommonGroups SET
		ModUserNo = organization_updatecommongroup_name.moduserno,
		ModDate = organization_updatecommongroup_name.moddate,
