-- OBJECT ROUTINE public/dbo.permission_getpermissionlevel
CREATE OR REPLACE FUNCTION public.permission_getpermissionlevel(userno integer)
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN


	RETURN QUERY
	SELECT UserNo, RegUserNo, RegDate, ModUserNo, ModDate, Level
	FROM PermissionLevels
	WHERE UserNo = permission_getpermissionlevel.userno;
END;
$function$


-- OBJECT ROUTINE public/dbo.permission_getusermenulist
CREATE OR REPLACE FUNCTION public.permission_getusermenulist()
 RETURNS SETOF record
 LANGUAGE plpgsql
AS $function$
-- !! WARNING: output needs manual review — see TODO comments
BEGIN

	RETURN QUERY
	SELECT 
		UM.MenuNo, 
		MM.MenuName, 
		MM.MenuEngName,
		MM.MenuJpnName,
		MM.MenuChaName,
		MM.ServiceNo, 
		MM.ServiceTag, 
		MM.ServiceUrl, 
		UM.Level, 
		MM.PermissionLevel
	FROM PermissionLevelsUserMenu UM
	LEFT JOIN Biz_Center.public."MainMenuList" MM ON UM.MenuNo = MM.MenuNo
	WHERE UM.UserNo = UserNo
	AND UM.Level <= MM.PermissionLevel;
END;
$function$


-- OBJECT ROUTINE public/dbo.uf_departmentbranchname
CREATE OR REPLACE FUNCTION public.uf_departmentbranchname(userno integer)
 RETURNS character varying
 LANGUAGE plpgsql
AS $function$
BEGIN


    with name_tree as 
	(
 		SELECT DepartNo, ParentNo, Name, Name_EN 
		      ,1 AS CatLevel
		FROM Organization_Departments 
		WHERE DepartNo IN (
			SELECT DepartNo FROM Organization_BelongToDepartment 
			WHERE UserNo = uf_departmentbranchname.userno
		)
	   union all
	   select C.DepartNo, C.ParentNo, c.Name, c.Name_EN
			  , 1 || CatLevel
	   from Organization_Departments c
	   join name_tree p on C.DepartNo = P.ParentNo  
		AND C.DepartNo<>C.ParentNo 
	) 
	select  Name = tr.Name 
	from name_tree tr where tr.CatLevel = 2;
	RETURN Name;
END;
$function$


